import FONTS from '@/game/constants/resources/fonts'
import { getPreviewClass } from '../preview'
import BasePreview from '../preview/BasePreview'

class ObjectCountBlock extends Phaser.GameObjects.Container {
    public preview: BasePreview
    public countText: Phaser.GameObjects.BitmapText
    public groupText: Phaser.GameObjects.BitmapText

    constructor(scene: Phaser.Scene, type: string) {
        super(scene, 0, 0)

        this.createPreview(type)
        this.createCountText()
        this.createGroupText()
    }

    private createGroupText() {
        this.groupText = this.scene.make.bitmapText({
            font: FONTS.PRIMARY.KEY,
            size: this.scene.fontSize(20),
        })
        this.groupText.kill()
        this.add(this.groupText)
    }

    private createPreview(type: string) {
        const PreviewClass = getPreviewClass(type)
        this.preview = new PreviewClass(this.scene)

        this.preview.setPosition(-20, 0)

        this.add(this.preview)
    }

    private createCountText() {
        this.countText = this.scene.add.bitmapText(
            0,
            0,
            FONTS.PRIMARY.KEY,
            '0',
            this.scene.fontSize(20)
        )
        this.countText.setPosition(17, 0)
        this.add(this.countText)
    }

    public setCountText(count: number) {
        this.countText.setText(`${count}`)
        Phaser.Display.Align.To.RightCenter(this.countText, this)
    }

    public setGroupText(group: number) {
        this.groupText.setText(`${group}`)
    }

    public align(isShowGroupText = false): void {
        if (isShowGroupText) {
            this.groupText.revive()
            Phaser.Display.Align.To.RightCenter(this.countText, this, 0, -8)
            Phaser.Display.Align.To.RightCenter(this.groupText, this, 0, 8)
        } else {
            this.groupText.kill()
            Phaser.Display.Align.To.RightCenter(this.countText, this)
        }
    }
}

export default ObjectCountBlock
