import SPRITES from '@/game/constants/resources/sprites'

import ColorBallPreview from './ColorBallPreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS
class QuestionMarkBallPreview extends ColorBallPreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'QuestionMarkBall'

        const questionMarkFrame = scene.make.image({
            key: KEY,
            frame: FRAME.BALL_QUESTION_MARK,
        })
        questionMarkFrame.setWorldSize(34, 34)
        this.add(questionMarkFrame)
        scene.add.existing(this)
    }
}

export default QuestionMarkBallPreview
