import GridTile from '../editor/tiles/GridTile'
import GridEditor from '../GridEditor'
import { BaseFunction } from './BaseFunction'

class SelectSameGridTilesFunction extends BaseFunction {
    public sameGridTiles: GridTile[] = []
    constructor(gridEditor: GridEditor) {
        super(gridEditor)
    }

    public select(gridTiles: GridTile[]): void {
        this.sameGridTiles = []
        if (gridTiles.length === 0) return

        const topLeftGridTile = this.getTopLeftInGridTiles(gridTiles)
        const sameGridTiles = this.gridEditor.getSameGridTilesSpreadFrom(topLeftGridTile)
        if (sameGridTiles.length === 0) return

        this.gridEditor.unSelectAll()
        sameGridTiles.forEach((gridTiles) => {
            gridTiles.forEach((gridTile) => {
                gridTile.select()
            })
        })
    }

    public selectAllSameGridTile(gridTiles: GridTile[]): void {
        this.sameGridTiles = []
        if (gridTiles.length === 0) return

        const topLeftGridTile = this.getTopLeftInGridTiles(gridTiles)
        const sameGridTiles = this.gridEditor.getSameGridTiles(topLeftGridTile)
        if (sameGridTiles.length === 0) return

        this.gridEditor.unSelectAll()
        sameGridTiles.forEach((gridTile) => {
            gridTile.select()
        })
    }
}

export default SelectSameGridTilesFunction
