import GridEditor, { GridTileGroupData } from '../../GridEditor'
import GridTile from '../tiles/GridTile'

class CountManager {
    private count: { [key: string]: number } = {}
    private countSpecial: { [key: string]: number } = {}

    public countGroup: {
        [key: string]: number
    } = {}

    public updateCount(gridTiles: GridTile[][]) {
        this.count = {}
        gridTiles.forEach((r) => {
            r.forEach((gridTile) => {
                const preview = gridTile.preview
                const subObjects = gridTile.subObjectsPreview
                if (!preview.typePreview) return

                this.count[preview.typePreview] = this.count[preview.typePreview]
                    ? this.count[preview.typePreview] + 1
                    : 1

                subObjects.forEach((subObject) => {
                    this.count[subObject.typePreview] = this.count[subObject.typePreview]
                        ? this.count[subObject.typePreview] + 1
                        : 1
                })
            })
        })
    }

    public updateCountSpecial(gridTiles: GridTile[]) {
        this.countSpecial = {}
        gridTiles.forEach((gridTile) => {
            const preview = gridTile.preview
            const subObjects = gridTile.subObjectsPreview
            if (!preview.typePreview) return

            this.countSpecial[preview.typePreview] = this.countSpecial[preview.typePreview]
                ? this.countSpecial[preview.typePreview] + 1
                : 1

            subObjects.forEach((subObject) => {
                this.countSpecial[subObject.typePreview] = this.countSpecial[subObject.typePreview]
                    ? this.countSpecial[subObject.typePreview] + 1
                    : 1
            })
        })
    }

    public getCount(): { [key: string]: number } {
        return this.count
    }

    public getCountSpecial(): { [key: string]: number } {
        return this.countSpecial
    }

    public getCountGroup(): { [key: string]: number } {
        return this.countGroup
    }

    public updateCountGroup(gridEditor: GridEditor): void {
        this.countGroup = {}
        const groupsData = gridEditor.getGridTileGroupsData()
        groupsData.forEach((data: GridTileGroupData) => {
            if (data.type) {
                this.countGroup[data.type] = (this.countGroup[data.type] || 0) + 1
            }
        })
    }
}

export default CountManager
