import SPRITES from '@/game/constants/resources/sprites'
import Base2Preview from './Base2Preview'
import Direction from '@/game/gameplay/types/Direction'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class WhirlDirectionPreview extends Base2Preview {
    private ballImage: Phaser.GameObjects.Image
    private arrowImage: Phaser.GameObjects.Image
    private circle: Phaser.GameObjects.Image
    private reverseArrowCircle: Phaser.GameObjects.Image
    private advanceArrowCircle: Phaser.GameObjects.Image
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'WhirlDirectionBall'

        this.ballImage = scene.make.image({
            key: KEY,
            frame: FRAME.COMPASS,
        })
        this.ballImage.setWorldSize(34, 34)

        this.arrowImage = scene.make.image({
            key: KEY,
            frame: FRAME.COMPASS_NEEDLE,
        })
        this.arrowImage.setWorldSize(34, 34)

        this.createCircles()

        this.setSize(34, 34)

        this.add([
            this.ballImage,
            this.arrowImage,
            this.circle,
            this.reverseArrowCircle,
            this.advanceArrowCircle,
        ])

        scene.add.existing(this)
    }

    private createCircles() {
        this.reverseArrowCircle = this.scene.make.image({
            key: KEY,
            frame: FRAME.COMPASS_YELLOW_CIRCLE,
        })
        this.reverseArrowCircle.setWorldSize(80 * 0.5, 61.5 * 0.5)

        this.advanceArrowCircle = this.scene.make.image({
            key: KEY,
            frame: FRAME.COMPASS_BLUE_CIRCLE,
        })
        this.advanceArrowCircle.setWorldSize(73.5 * 0.5, 58.5 * 0.5)
        this.circle = this.scene.make.image({
            key: KEY,
            frame: FRAME.COMPASS_CIRCLE,
        })
        this.circle.setWorldSize(68.5 * 0.5, 68.5 * 0.5)
    }

    public setStatus(value = 0): void {
        super.setStatus(value)
        switch (value) {
            case 2:
            case -2:
                this.ballImage.setRotation(Direction.UpLeft)
                this.arrowImage.setRotation(Direction.UpLeft)
                break
            case 3:
            case -3:
                this.ballImage.setRotation(Direction.UpRight)
                this.arrowImage.setRotation(Direction.UpRight)
                break
            case 4:
            case -4:
                this.ballImage.setRotation(Direction.Right)
                this.arrowImage.setRotation(Direction.Right)
                break
            case 1:
            case -1:
            default:
                this.ballImage.setRotation(Direction.Left)
                this.arrowImage.setRotation(Direction.Left)
                break
        }
        if (value < 0) {
            this.reverseArrowCircle.revive()
            this.advanceArrowCircle.kill()
            return
        }

        this.reverseArrowCircle.kill()
        this.advanceArrowCircle.revive()
    }
}

export default WhirlDirectionPreview
