import SPRITES from '@/game/constants/resources/sprites'
import { Color } from '@/game/gameplay/types/Color'
import ColorBallPreview from './ColorBallPreview'

const { KEY, FRAME } = SPRITES.FIRST_10_LEVELS_GAME_OBJECTS

class GemBallPreview extends ColorBallPreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'GemBall'

        const gemFrame = scene.make.image({
            key: KEY,
            frame: FRAME.BALL_TRANSPARENT,
        })
        gemFrame.setWorldSize(34, 34)
        this.add(gemFrame)
        this.sendToBack(gemFrame)

        this.image.setTexture(SPRITES.DEFAULT.KEY)
        this.image.setFrame(SPRITES.DEFAULT.FRAME.BUY_ITEM_RAINBOW_BIG)
        this.image.setWorldSize(22, 22)

        this.randomImage.kill()

        scene.add.existing(this)
    }

    setColor(color?: number): void {
        this.color = color || -1
        this.image.setTexture(KEY)
        switch (color) {
            case Color.Red:
                this.image.setFrame(FRAME.GEM_RED)
                break

            case Color.Green:
                this.image.setFrame(FRAME.GEM_GREEN)
                break

            case Color.Blue:
                this.image.setFrame(FRAME.GEM_BLUE)
                break

            case Color.Yellow:
                this.image.setFrame(FRAME.GEM_YELLOW)
                break

            case Color.Pink:
                this.image.setFrame(FRAME.GEM_PINK)
                break

            case Color.Violet:
                this.image.setFrame(FRAME.GEM_PURPLE)
                break

            case Color.Cyan:
                this.image.setFrame(FRAME.GEM_CYAN)
                break

            case Color.Orange:
                this.image.setFrame(FRAME.GEM_ORANGE)
                break

            default:
                this.image.setTexture(SPRITES.DEFAULT.KEY)
                this.image.setFrame(SPRITES.DEFAULT.FRAME.BUY_ITEM_RAINBOW_BIG)
        }
    }

    setRandomColor() {
        this.color = -1
        this.image.setTexture(SPRITES.DEFAULT.KEY)
        this.image.setFrame(SPRITES.DEFAULT.FRAME.BUY_ITEM_RAINBOW_BIG)

        this.image.setAlpha(0.8)
    }
}

export default GemBallPreview
