import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class ThreeThundersBallPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'ThreeThundersBall'

        const ball = scene.make.image({
            key: KEY,
            frame: FRAME.THREE_THUNDERS_BALL,
        })

        ball.setWorldSize(34, 34)

        const radius = 8
        const step = (Math.PI * 2) / 3
        const scale = 1 / this.scene.world.getPixelRatio()

        for (let i = 0; i < 3; i++) {
            const image = scene.make.image({
                key: KEY,
                frame: FRAME.THREE_THUNDERS_BALL_THUNDER,
            })
            image.setScale(scale * 0.9)
            image.setPosition(
                this.x + radius * Math.cos(0 - step * i),
                this.y + radius * Math.sin(0 - step * i)
            )
            image.setAngle(22)
            this.add(image)
        }

        this.setSize(34, 34)

        this.add([ball])

        scene.add.existing(this)
    }
}

export default ThreeThundersBallPreview
