import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class RotationWheelPreview extends BasePreview {
    public image: Phaser.GameObjects.Image
    private rotatorImage: Phaser.GameObjects.Image

    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'RotationWheel'

        this.createRotatorImage()

        const image = scene.make.image({
            key: KEY,
            frame: FRAME.MOVE_ROTATION_BALL,
        })
        image.setWorldSize(32, 32)
        this.setSize(34, 34)
        this.image = image
        this.add(image)
        scene.add.existing(this)
    }

    private createRotatorImage(): void {
        this.rotatorImage = this.scene.make.image({
            key: KEY,
            frame: FRAME.ROTATOR,
        })
        this.rotatorImage.setWorldSize(32 * 3, 32 * 3)

        this.add(this.rotatorImage)
    }
}

export default RotationWheelPreview
