import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.FIRST_10_LEVELS_GAME_OBJECTS
const { KEY: KEY_GAME_OBJECTS, FRAME: FRAME_GAME_OBJECTS } = SPRITES.GAMEPLAY.GAME_OBJECTS

class KeyBallPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'KeyBall'

        const image = scene.make.image({
            key: KEY,
            frame: FRAME.BALL_TRANSPARENT,
        })
        image.setWorldSize(34, 34)

        const key = scene.make.image({
            key: KEY_GAME_OBJECTS,
            frame: FRAME_GAME_OBJECTS.KEY,
        })
        key.setWorldSize(25, 28)

        this.setSize(34, 34)

        this.add([image, key])

        scene.add.existing(this)
    }
}

export default KeyBallPreview
