import Button from '@/game/components/Button'
import Scroller from '@/game/components/Scroller'
import FONTS from '@/game/constants/resources/fonts'
import SPRITES from '@/game/constants/resources/sprites'
import { SceneKeys } from '@/game/constants/scenes'
import { ScreenKeys } from '@/game/constants/screens'
import LevelEditorScene from '../../LevelEditorScene'

const { KEY, FRAME } = SPRITES.EDITOR
class levelEditorBottom extends Phaser.GameObjects.Container {
    declare scene: LevelEditorScene

    private background: Phaser.GameObjects.Rectangle
    public copyButton: Button
    public removeButton: Button
    public createButton: Button
    public saveButton: Button
    public playButton: Button

    public exitButton: Button

    public separator1: Phaser.GameObjects.Image
    public separator2: Phaser.GameObjects.Image

    public prevLevelButton: Button
    public nextLevelButton: Button
    public textCurrentLevel: Phaser.GameObjects.BitmapText
    public levelRectangle: Phaser.GameObjects.Rectangle

    public levelRectangle2: Phaser.GameObjects.Graphics

    public levelScroller: Scroller

    private isOpenCopy = false
    private isOpenDelete = false
    constructor(scene: Phaser.Scene) {
        super(scene)
        this.createUI()

        this.algin()
        this.alignLevelButton()

        this.setSize(this.background.width, this.background.height)
    }

    private createUI(): void {
        this.createBackground()
        this.createButtons()
        this.createNextLevelBtn()
        this.createPrevLevelBtn()
        this.createExitButton()
        this.createSeparates()
        this.createLevel()
        //
    }

    public updateLevel() {
        const level = this.scene.level.getLevel()
        this.textCurrentLevel.setText(`Level ${level}`)
        Phaser.Display.Align.In.Center(this.textCurrentLevel, this.levelRectangle)
    }

    private createBackground(): void {
        this.background = this.scene.add.rectangle(0, 0, 375, 60, 0, 0.5)
        this.background.setOrigin(0.5, 0.5)
        this.add(this.background)
    }

    private createButtons(): void {
        this.copyButton = new Button(this.scene, KEY, FRAME.SWAP_ICON, 30, 30)
        this.removeButton = new Button(this.scene, KEY, FRAME.REMOVE_ICON, 30, 30)
        this.playButton = new Button(this.scene, KEY, FRAME.PLAY_ICON, 30, 30)
        this.createButton = new Button(this.scene, KEY, FRAME.CREATE_ICON, 30, 30)
        this.saveButton = new Button(this.scene, KEY, FRAME.SAVE_ICON, 30, 30)
        this.add([
            this.copyButton,
            this.removeButton,
            this.createButton,
            this.saveButton,
            this.playButton,
        ])

        this.copyButton.onClick = () => {
            if (this.isOpenCopy) return

            this.isOpenCopy = true
            const levelCopyInput = document.createElement('input')
            levelCopyInput.id = 'level-copy-input'
            levelCopyInput.style.width = '150px'
            levelCopyInput.style.height = '25px'
            levelCopyInput.style.top = '10px'
            levelCopyInput.style.left = '50%'
            levelCopyInput.style.marginLeft = '-75px'
            levelCopyInput.style.position = 'fixed'
            levelCopyInput.type = 'number'
            levelCopyInput.min = '1'
            levelCopyInput.style.zIndex = '10000'
            levelCopyInput.placeholder = 'Level to copy'

            const copyButton = document.createElement('button')
            copyButton.id = 'copy-button'
            copyButton.style.width = '75px'
            copyButton.style.height = '25px'
            copyButton.style.top = '50px'
            copyButton.style.left = '50%'
            copyButton.style.marginLeft = '-100px'
            copyButton.style.position = 'fixed'
            copyButton.innerText = 'Copy'
            copyButton.style.zIndex = '10000'
            copyButton.onclick = async () => {
                const currentLevel = this.scene.level.getLevel()

                try {
                    this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                        message: 'Loading...',
                        duration: 0,
                        loading: true,
                    })

                    const levelToCopy = parseInt(levelCopyInput.value)

                    const levelDataToCopy = await this.scene.level.getLevelDataAsync(levelToCopy)

                    if (!levelDataToCopy) {
                        throw new Error('Not level data')
                    }

                    this.scene.level.setLevel(currentLevel)
                    await this.saveLevelData(levelDataToCopy)

                    this.scene.updateLevelData(levelDataToCopy)

                    this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                        message: 'Action Successfully',
                        duration: 1500,
                        loading: false,
                    })
                } catch {
                    this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                        message: 'Action Error',
                        duration: 1500,
                        loading: false,
                    })
                }
                document.body.removeChild(levelCopyInput)
                document.body.removeChild(copyButton)
                document.body.removeChild(cancelButton)
                this.isOpenCopy = false
            }

            const cancelButton = document.createElement('button')
            cancelButton.id = 'cancel-copy-button'
            cancelButton.style.width = '75px'
            cancelButton.style.height = '25px'
            cancelButton.style.top = '50px'
            cancelButton.style.left = '50%'
            cancelButton.style.marginLeft = '25px'
            cancelButton.style.position = 'fixed'
            cancelButton.innerText = 'Cancel'
            cancelButton.style.zIndex = '10000'
            cancelButton.onclick = () => {
                document.body.removeChild(levelCopyInput)
                document.body.removeChild(copyButton)
                document.body.removeChild(cancelButton)
                this.isOpenCopy = false
            }

            document.body.appendChild(levelCopyInput)
            document.body.appendChild(copyButton)
            document.body.appendChild(cancelButton)
        }

        this.createButton.onClick = async () => {
            const levelMap = this.scene.level.getLevelConfigMap()
            const level = levelMap.length + 1
            await this.changeToLevel(level)
        }

        this.removeButton.onClick = this.removeLevelData

        this.saveButton.onClick = () => this.saveLevelData(this.scene.getLevelData())

        this.playButton.onClick = this.scene.handlePlayTest
    }

    private changeToLevel = async (level: number) => {
        this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
            message: 'Loading...',
            duration: 0,
            loading: true,
        })
        try {
            this.scene.level.setLevel(level)
            const levelData = await this.scene.level.getLevelDataAsync()
            if (!levelData) {
                await this.saveLevelData(this.scene.getDefaultLevelData())
                await this.changeToLevel(level)
            } else {
                this.scene.updateLevelData(levelData)
            }

            this.textCurrentLevel.setText(`Level ${level}`)

            this.scene.game.globalScene.screen.close(ScreenKeys.NOTIFY_SCREEN)
        } catch {
            this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                message: 'Action Error',
                duration: 1500,
                loading: false,
            })
        }
    }

    private removeLevelData = () => {
        if (this.isOpenDelete) return

        this.isOpenDelete = true
        const level = this.scene.level.getLevel()

        const levelMap = this.scene.level.getLevelConfigMap()
        const l: BubblePopOrigin.Data.ILevelButtonConfig | undefined = levelMap.find(
            (x) => x.level === level
        )
        if (!l) return

        const deleteButton = document.createElement('button')
        deleteButton.id = 'delete-button'
        deleteButton.style.width = '180px'
        deleteButton.style.height = '25px'
        deleteButton.style.top = '20px'
        deleteButton.style.left = '50%'
        deleteButton.style.marginLeft = '-90px'
        deleteButton.style.position = 'fixed'
        deleteButton.innerText =
            levelMap.indexOf(l) === levelMap.length - 1
                ? `Delete level ${level}`
                : `Reset level ${level} to default`
        deleteButton.style.zIndex = '10000'
        deleteButton.onclick = async () => {
            // last level
            if (levelMap.indexOf(l) === levelMap.length - 1) {
                this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                    message: 'Loading...',
                    duration: 0,
                    loading: true,
                })

                try {
                    const urlEditLevel = GameCore.Configs.Level.urlEditLevel

                    const x = levelMap.pop()

                    const body = {
                        name: this.scene.level.getKeyLevel(level),
                        levelMap: { levelMap: x },
                    }

                    const result = await fetch(`${urlEditLevel}remove`, {
                        method: 'DELETE',
                        headers: {
                            Accept: 'application/json',
                            'Content-Type': 'application/json',
                        },
                        body: JSON.stringify(body),
                    })

                    await this.changeToLevel(level - 1)

                    this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                        message: 'Remove Successfully',
                        duration: 1500,
                        loading: false,
                    })
                } catch {
                    this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                        message: 'Remove Error',
                        duration: 1500,
                        loading: false,
                    })
                }
            } else {
                this.scene.updateLevelData(this.scene.getDefaultLevelData())
                await this.saveLevelData(this.scene.getLevelData())
            }
            document.body.removeChild(deleteButton)
            document.body.removeChild(cancelButton)

            this.isOpenDelete = false
        }

        const cancelButton = document.createElement('button')
        cancelButton.id = 'cancel-delete-button'
        cancelButton.style.width = '100px'
        cancelButton.style.height = '25px'
        cancelButton.style.top = '50px'
        cancelButton.style.left = '50%'
        cancelButton.style.marginLeft = '-50px'
        cancelButton.style.position = 'fixed'
        cancelButton.innerText = 'Cancel'
        cancelButton.style.zIndex = '10000'
        cancelButton.onclick = () => {
            document.body.removeChild(deleteButton)
            document.body.removeChild(cancelButton)

            this.isOpenDelete = false
        }

        document.body.appendChild(deleteButton)
        document.body.appendChild(cancelButton)
    }

    private saveLevelData = async (levelData: BubblePopOrigin.Data.ILevelData) => {
        this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
            message: 'Loading...',
            duration: 0,
            loading: true,
        })

        try {
            const urlEditLevel = GameCore.Configs.Level.urlEditLevel

            const level = this.scene.level.getLevel()

            const levelMap = this.scene.level.getLevelConfigMap()
            let l: BubblePopOrigin.Data.ILevelButtonConfig | undefined = levelMap.find(
                (x) => x.level === level
            )

            if (!l) {
                l = {
                    isHard: false,
                    level: level,
                    missionType: 'CollectBubbles',
                    colorButtonOverlay: 'orange',
                }
                levelMap.push(l)
            }

            l.isHard = levelData.isHard
            l.level = level
            l.missionType = levelData.missionType
            l.colorButtonOverlay = levelData.colorButtonOverlay
            l.treasure = levelData.treasure

            console.log({ levelMap })

            const body = {
                name: this.scene.level.getKeyLevel(level),
                levelData: levelData,
                // levelMap: { levelMap },
                levelSummary: l,
            }

            const result = await fetch(`${urlEditLevel}uploads`, {
                method: 'POST',
                headers: {
                    Accept: 'application/json',
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(body),
            })

            console.log(result)

            this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                message: 'Action Successfully',
                duration: 1500,
                loading: false,
            })
        } catch (e) {
            console.log(e)
            this.scene.game.globalScene.screen.open(ScreenKeys.NOTIFY_SCREEN, {
                message: 'Action Error',
                duration: 1500,
                loading: false,
            })
        }
    }

    private createExitButton(): void {
        this.exitButton = new Button(this.scene, KEY, FRAME.EXIT_ICON, 30, 30)
        this.add(this.exitButton)

        this.exitButton.onClick = this.scene.handleExit
    }

    private createPrevLevelBtn(): void {
        this.prevLevelButton = new Button(this.scene, KEY, FRAME.BUTTON_PREV_LEVEL, 23, 29)
        this.add(this.prevLevelButton)

        this.prevLevelButton.onClick = () => {
            const level = this.scene.level.getLevel()
            this.changeToLevel(level - 1 > 0 ? level - 1 : 1)
        }
    }

    private createNextLevelBtn(): void {
        this.nextLevelButton = new Button(this.scene, KEY, FRAME.BUTTON_NEXT_LEVEL, 23, 29)
        this.add(this.nextLevelButton)

        this.nextLevelButton.onClick = () => {
            const level = this.scene.level.getLevel()
            this.changeToLevel(level + 1)
        }
    }

    private createSeparates(): void {
        this.separator1 = this.scene.make.image({
            key: KEY,
            frame: FRAME.PANEL_SEPARATOR,
        })

        this.separator1.setWorldSize(2, 19)

        this.separator2 = this.scene.make.image({
            key: KEY,
            frame: FRAME.PANEL_SEPARATOR,
        })

        this.separator2.setWorldSize(2, 19)

        this.add([this.separator1, this.separator2])
    }

    private createLevel(): void {
        const level = this.scene.level.getLevel()
        this.levelRectangle = this.scene.add.rectangle(0, 0, 60, 27, 0, 0)
        this.levelRectangle.setStrokeStyle(1, 0xffffff, 0.5)
        const text = `Level ${level}`
        this.textCurrentLevel = this.scene.make.bitmapText({
            font: FONTS.PRIMARY.KEY,
            text,
            size: this.scene.fontSize(13),
        })
        this.levelRectangle2 = this.scene.add.graphics()
        this.levelRectangle2.lineStyle(1, 0xffffff, 0.5)
        this.levelRectangle2.strokeRoundedRect(0, 0, 60, 20, {
            tl: 2,
            tr: 2,
            bl: 2,
            br: 2,
        })

        this.levelScroller = new Scroller(this.scene, {
            width: 150,
            height: 300,
            marginBottom: 0,
            marginTop: 0,
        })

        const blank = this.scene.make.image({
            key: KEY,
            frame: FRAME.BLANK,
            alpha: 0.5,
            tint: 0,
        })
        blank.setTint(0)
        blank.setWorldSize(150, 300)

        this.levelScroller.add(blank)
        this.levelScroller.sendToBack(blank)
        this.levelScroller.createMask()
        this.levelScroller.setEnable(true)
        this.levelScroller.kill()
        this.levelScroller.setPosition(-130, -180)

        this.levelRectangle.setInteractive()
        this.levelRectangle.on(Phaser.Input.Events.POINTER_DOWN, () => {
            this.handleAddChangeLevel()
            // if (this.levelScroller.active) {
            //     this.levelScroller.kill()
            // } else {
            //     this.levelScroller.clearItem()

            //     const levelMapConfig = this.scene.level.getLevelConfigMap()
            //     levelMapConfig.forEach((config, i) => {
            //         const button = new LevelButton(this.scene, config.level)
            //         button.setPosition(0, -187.5 + 25 * i)
            //         button.onClick = () => {
            //             this.changeToLevel(config.level)
            //             this.levelScroller.kill()
            //         }

            //         this.levelScroller.addItem(button)
            //     })

            //     this.levelScroller.setEnable(true)
            //     this.levelScroller.revive()
            //     this.levelScroller.sendToBack(blank)
            // }
        })

        this.add(this.levelScroller)

        Phaser.Display.Align.In.Center(this.levelRectangle2, this.background)
        this.add([this.levelRectangle, this.textCurrentLevel, this.levelRectangle2])
    }

    private algin(): void {
        const buttonsGap = 5
        const separatorGap = 8
        Phaser.Display.Align.In.RightCenter(this.exitButton, this.background, -separatorGap)
        Phaser.Display.Align.To.LeftCenter(this.playButton, this.exitButton, separatorGap * 2)

        Phaser.Display.Align.To.LeftCenter(this.saveButton, this.playButton, buttonsGap)
        Phaser.Display.Align.To.LeftCenter(this.createButton, this.saveButton, buttonsGap)
        Phaser.Display.Align.To.LeftCenter(this.removeButton, this.createButton, buttonsGap)
        Phaser.Display.Align.To.LeftCenter(this.copyButton, this.removeButton, buttonsGap)

        Phaser.Display.Align.In.LeftCenter(this.separator1, this.exitButton, separatorGap)
        Phaser.Display.Align.In.LeftCenter(this.separator2, this.copyButton, separatorGap)
    }

    private alignLevelButton(): void {
        const margin = 5
        Phaser.Display.Align.In.LeftCenter(this.levelRectangle, this.background, -30)

        Phaser.Display.Align.In.Center(this.textCurrentLevel, this.levelRectangle)
        Phaser.Display.Align.To.LeftCenter(this.prevLevelButton, this.levelRectangle, margin)
        Phaser.Display.Align.To.RightCenter(this.nextLevelButton, this.levelRectangle, margin)
    }

    private handleAddChangeLevel = () => {
        const level = this.scene.level.getLevel()
        const boundRectCanvas = this.scene.game.canvas.getBoundingClientRect()
        const { width, height } = this.scene.world.getWorldSize()

        const worldPositionPrevLevelBtn = this.prevLevelButton.getWorldPosition()
        const levelMapConfig = this.scene.level.getLevelConfigMap()
        const levelInput = document.createElement('input')
        levelInput.id = 'row-input'

        levelInput.style.width = `${56 * (boundRectCanvas.width / width)}px`
        levelInput.style.height = `${24 * (boundRectCanvas.height / height)}px`
        levelInput.style.bottom = `${(15 * boundRectCanvas.height) / height}px`
        levelInput.style.left = `${
            boundRectCanvas.x +
            (this.background.width / 2 + this.levelRectangle.x) * (boundRectCanvas.width / width) -
            31 * (boundRectCanvas.width / width)
        }px`
        levelInput.style.position = 'fixed'
        levelInput.style.textAlign = 'center'
        levelInput.style.fontSize = `${12 * (boundRectCanvas.width / width)}px`
        levelInput.type = 'number'
        levelInput.style.zIndex = '10000'
        levelInput.value = `${level}`
        levelInput.min = '1'

        levelInput.autofocus = true

        const cancelButton = document.createElement('button')
        cancelButton.id = 'cancel-add-row-button'
        cancelButton.style.width = '75px'
        cancelButton.style.height = '25px'

        cancelButton.style.bottom = `${(50 * boundRectCanvas.height) / height}px`
        cancelButton.style.left = `${
            boundRectCanvas.x +
            (this.background.width / 2 + this.levelRectangle.x) * (boundRectCanvas.width / width) -
            40 * (boundRectCanvas.width / width)
        }px`

        cancelButton.style.marginLeft = '25px'
        cancelButton.style.position = 'fixed'
        cancelButton.innerText = 'Cancel'
        cancelButton.style.zIndex = '10000'

        const event = (e: KeyboardEvent) => {
            if (e.key === 'Enter') {
                document.removeEventListener('keypress', event)
                document.body.removeChild(cancelButton)
                document.body.removeChild(levelInput)

                const levelChange = parseInt(levelInput.value)

                if (
                    !this.scene.scene.isVisible(SceneKeys.LEVEL_EDITOR_SCENE) ||
                    levelChange <= 0 ||
                    levelChange === level ||
                    levelChange > levelMapConfig.length
                )
                    return

                this.changeToLevel(levelChange)
            }
        }

        cancelButton.onclick = () => {
            document.body.removeChild(levelInput)
            document.body.removeChild(cancelButton)
            document.removeEventListener('keypress', event)
        }

        document.addEventListener('keypress', event)
        document.body.appendChild(levelInput)
        document.body.appendChild(cancelButton)
    }
}

class LevelButton extends Button {
    constructor(scene: Phaser.Scene, level: number) {
        super(scene, KEY, FRAME.BLANK, 80, 25)
        this.button.setTint(0)
        const text = scene.make.bitmapText({
            font: FONTS.PRIMARY.KEY,
            text: `level ${level}`,
            size: scene.fontSize(12),
            origin: { x: 0.5, y: 0.5 },
        })

        this.add(text)
    }
}
export default levelEditorBottom
