import SPRITES from '@/game/constants/resources/sprites'
import { SceneEvents, SceneKeys } from '@/game/constants/scenes'
import { debounce } from 'ts-debounce'
import BaseScene from '../BaseScene'
import LevelDataPanel from './editor/panels/LevelDataPanel'
import BulletEditor from './BulletEditor'
import GridEditor from './GridEditor'
import LevelEditorGui from './level-editor-gui/LevelEditorGui'
import { startSingleModeGame } from '@/modules/match/actions/gameplay'
import CountManager from './editor/count-objects/CountManager'
import CountContainer from './editor/count-objects/CountContainer'
import FONTS from '@/game/constants/resources/fonts'

const { KEY, FRAME } = SPRITES.EDITOR

class LevelEditorScene extends BaseScene {
    public currentLevel: number
    public currentLevelData: BubblePopOrigin.Data.ILevelData
    public levelEditorGui: LevelEditorGui

    public gridEditor: GridEditor
    public bulletEditor: BulletEditor

    public levelDataPanel: LevelDataPanel

    public countManager: CountManager
    public countContainer: CountContainer

    private warningBackground: Phaser.GameObjects.Image
    private warningText: Phaser.GameObjects.BitmapText
    private warningContainer: Phaser.GameObjects.Container

    public preload(): void {
        this.load.atlas({
            key: KEY,
            textureURL: SPRITES.EDITOR.TEXTURE,
            atlasURL: SPRITES.EDITOR.JSON,
        })

        this.events.on(Phaser.Scenes.Events.WAKE, this.run)
        this.events.on(Phaser.Scenes.Events.CREATE, this.run)

        this.input.keyboard.on('keydown-ESC', this.handleExit)
    }

    private run = (): void => {
        this.currentLevel = this.level.getLevel()
        this.updateLevelData(this.level.getLevelData() || defaultLevelData())
    }

    public updateLevelData(levelData: BubblePopOrigin.Data.ILevelData) {
        Phaser.Display.Align.In.Center(this.background, this.gameZone, 0, 0)
        Phaser.Display.Align.In.BottomCenter(this.levelEditorGui, this.gameZone, 0, -30)
        Phaser.Display.Align.In.TopLeft(this.countContainer, this.gameZone, 0, 0)
        Phaser.Display.Align.In.TopCenter(this.warningContainer, this.gameZone, 0, -25)

        this.currentLevelData = levelData
        this.gridEditor.setGridData(this.currentLevelData.grid)

        this.levelDataPanel.setData(this.currentLevelData)
        this.levelDataPanel.setEnable(true)
        this.bulletEditor.setBulletsData(this.currentLevelData.bulletsColor)
        this.levelEditorGui.levelEditorBottom.updateLevel()
    }

    public create = (): void => {
        super.create()
        this.createBackground(KEY, FRAME.BACKGROUND)

        this.createLevelDataPanel()
        this.createLevelEditorGui()
        this.createCountContainer()
        this.createWarning()

        this.cameras.main.startFollow(this.background)

        this.input.on('wheel', this.onMouseScroll)

        this.input.setTopOnly(true)

        this.gridEditor = new GridEditor(this)

        this.bulletEditor = new BulletEditor(this)
        this.bulletEditor.setPosition(375 / 2, 0)

        this.countManager = new CountManager()
    }

    private createWarning() {
        this.warningBackground = this.add.image(0, 0, KEY, FRAME.BLANK)
        this.warningBackground.setWorldSize(375, 50)
        this.warningBackground.setTint(0x000000)

        this.warningText = this.add.bitmapText(0, 0, FONTS.PRIMARY.KEY, '', this.fontSize(20))
        this.warningText.setCenterAlign()
        this.warningText.setOrigin(0.5, 0.5)

        this.warningContainer = this.add.container(375 / 2, 25)
        this.warningContainer.add([this.warningBackground, this.warningText])
        this.warningContainer.setAlpha(0.9)
        this.warningContainer.setDepth(200000)
    }

    private onMouseScroll = debounce(
        (
            pointer: Phaser.Input.Pointer,
            gameObjects: unused,
            deltaX: unused,
            deltaY: number
        ): void => {
            this.background.y -= deltaY
            this.levelEditorGui.y -= deltaY
            this.warningContainer.y -= deltaY
        },
        100,
        { isImmediate: true, maxWait: 100 }
    )

    private createLevelEditorGui(): void {
        this.levelEditorGui = new LevelEditorGui(this)
        this.levelEditorGui.setDepth(5000)
        Phaser.Display.Align.In.BottomCenter(this.levelEditorGui, this.gameZone, 0, -30)
    }

    private createCountContainer(): void {
        this.countContainer = new CountContainer(this)
        this.countContainer.setDepth(199)
    }

    private createLevelDataPanel(): void {
        this.levelDataPanel = new LevelDataPanel(this)
    }

    public getLevelData() {
        const levelData = this.currentLevelData

        levelData.grid = this.gridEditor.getGridData()
        levelData.bulletsColor = this.bulletEditor.getBulletData()
        levelData.colors = this.gridEditor.getColors()

        const tweakpaneConfig = this.levelDataPanel.getData()

        console.log('tweakpaneConfig', { ...levelData, ...tweakpaneConfig })

        return { ...levelData, ...tweakpaneConfig }
    }

    public getDefaultLevelData = defaultLevelData

    public handlePlayTest = () => {
        const levelData = this.getLevelData()
        this.level.setLevelCustom(levelData)
        this.level.setMaxLevel(this.level.getLevel())

        console.log(this.level.getLevel())

        this.storage.dispatch(startSingleModeGame())
        this.levelDataPanel.setEnable(false)
    }

    public handleExit = () => {
        this.game.globalScene.events.emit(SceneEvents.SWITCH, SceneKeys.DASHBOARD_SCENE)
        this.levelDataPanel.setEnable(false)
    }

    update(time: number, delta: number): void {
        super.update(time, delta)
        this.countManager.updateCount(this.gridEditor.gridTiles)
        this.countManager.updateCountGroup(this.gridEditor)

        this.countContainer.updateObjects(
            this.countManager.getCount(),
            this.gridEditor.getColors(),
            this.countManager.getCountSpecial(),
            this.countManager.countGroup
        )

        this.updateWarning()
    }

    private updateWarning() {
        const colors = this.gridEditor.getColors()
        const colorsAccepted = [
            0xfc3d32, 0x026be3, 0x00e034, 0xffca00, 0xff00ff, 0x940f84, 0x0cb9f0, 0xf07214,
        ]
        const colorNotAccept = colors.find((c) => !colorsAccepted.includes(c))
        const gridData = this.gridEditor.getGridData()

        let isMissionValid = true
        let isHasGemBall = false
        for (let i = 0; i < gridData.length; i++) {
            const row = gridData[i]
            for (let j = 0; j < row.length; j++) {
                const object = row[j]
                if (object.objectType === 'GemBall') {
                    isHasGemBall = true
                    break
                }
            }
            if (isHasGemBall === true) break
        }

        const currentMission = this.levelDataPanel.getData().missionType
        isMissionValid =
            (currentMission === 'CollectBubbles' && !isHasGemBall) ||
            (currentMission === 'CollectGems' && isHasGemBall)

        if (!isMissionValid) {
            this.showWarningMissionType()
        } else if (colors.length === 0) {
            this.showWarningEmptyColors()
        } else if (colorNotAccept != undefined) {
            let x = -1
            let y = -1
            for (let i = 0; i < gridData.length; i++) {
                const row = gridData[i]
                for (let j = 0; j < row.length; j++) {
                    const object = row[j]
                    if (object.color === colorNotAccept || object.subColor === colorNotAccept) {
                        x = i + 1
                        y = j + 1
                        break
                    }
                }
                if (x != -1) break
            }
            this.showWarningColor(colorNotAccept, { x, y })
        } else {
            this.hideWarning()
        }
    }

    private showWarningMissionType() {
        this.warningContainer.setVisible(true)
        this.warningText.setText(`Current mission type is not correct`)
    }

    private showWarningEmptyColors() {
        this.warningContainer.setVisible(true)
        this.warningText.setText(`Current colors is empty!`)
    }

    private showWarningColor(color: number, position: IPosition) {
        this.warningContainer.setVisible(true)
        this.warningText.setText(`Color is not valid: ${color}, at (${position.x}, ${position.y})!`)
    }

    private hideWarning() {
        this.warningContainer.setVisible(false)
    }
}

export default LevelEditorScene

if (import.meta.hot) {
    import.meta.hot.accept(GameCore.LiveUpdate.Scene(SceneKeys.GAME_SCENE))
}

const defaultLevelData = (): BubblePopOrigin.Data.ILevelData => {
    return {
        isHard: false,
        enableConstraint: true,
        isBalanced: true,
        reduceOddBall: true,
        cantMatchBall: 5,
        minBallMatchGroup: 10,
        maxBallMatchGroup: 20,
        numberBullets: 20,
        bulletsColor: [],
        bulletItems: {
            BombBulletItem: 0,
            ElectricBulletBallItem: 0,
            RainbowBulletBallItem: 0,
            RocketBulletItem: 0,
        },
        starsTarget: [1000, 2000, 3000],
        missionType: 'CollectBubbles',
        colors: [16530738, 158691, 57396],
        grid: [[{}, {}, {}, {}, {}, {}, {}, {}, {}, {}, {}]],
        colorButtonOverlay: 'orange',
    }
}
