import BasePreview from './BasePreview'
import SPRITES from '@/game/constants/resources/sprites'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class SpiderPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)
        this.typePreview = 'Spider'

        const image = scene.make.image({
            key: KEY,
            frame: FRAME.SPIDER,
        })
        image.setWorldSize(18, 17.5)
        image.setFlipX(true)
        this.setSize(18, 17.5)

        this.add(image)
        image.setPosition(-8, -6)
        scene.add.existing(this)
    }
}

export default SpiderPreview
