import levelEditorBottom from './panels/LevelEditorBottom'

class LevelEditorGui extends Phaser.GameObjects.Container {
    public levelEditorBottom: levelEditorBottom
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.createUI()

        this.scene.add.existing(this)
    }

    private createUI(): void {
        this.levelEditorBottom = new levelEditorBottom(this.scene)
        this.add(this.levelEditorBottom)
    }
}
export default LevelEditorGui
