import SPRITES from '@/game/constants/resources/sprites'
import ColorBallPreview from './ColorBallPreview'

const { KEY, FRAME } = SPRITES.FIRST_10_LEVELS_GAME_OBJECTS

class ThunderBallPreview extends ColorBallPreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'ThunderBall'

        const thunder = scene.make.image({
            key: KEY,
            frame: FRAME.THUNDER_GLOW,
        })
        thunder.setTint(0xffff00)
        thunder.setWorldSize(16, 22)

        this.add(thunder)

        scene.add.existing(this)
    }
}

export default ThunderBallPreview
