import LevelEditorScene from './LevelEditorScene'
import GridTile from './editor/tiles/GridTile'
import SPRITES from '@/game/constants/resources/sprites'
import Button from '@/game/components/Button'
import PanelEditBullet from './editor/panels/PanelEditBullet'
import { Color } from '@/game/gameplay/types/Color'

const { KEY, FRAME } = SPRITES.EDITOR
class BulletEditor extends Phaser.GameObjects.Container {
    public scene: LevelEditorScene
    public bulletsData: number[] = []
    public gridTiles: GridTile[] = []

    public selectingTiles: GridTile[] = []

    private editBulletPanel: PanelEditBullet

    private selectState = 0

    public addNewBulletButton: Button
    public removeBulletButton: Button

    constructor(scene: LevelEditorScene) {
        super(scene)

        this.scene = scene

        this.addNewBulletButton = new Button(scene, KEY, FRAME.ADD_BUTTON, 34, 34)
        this.addNewBulletButton.onClick = this.handleAddBullet

        this.removeBulletButton = new Button(scene, KEY, FRAME.REMOVE_BUTTON, 20, 20)

        this.add([this.addNewBulletButton, this.removeBulletButton])

        this.createEditTilePanel()

        this.createListener()

        this.scene.add.existing(this)
    }

    private createListener() {
        this.scene.background.setInteractive()
        this.scene.background.on(Phaser.Input.Events.POINTER_DOWN, () => {
            this.editBulletPanel.closeExistPanel()
            this.unSelectAll()
        })
        this.scene.input.on(
            Phaser.Input.Events.GAMEOBJECT_DOWN,
            (pointer: Phaser.Input.Pointer, gameObject: any) => {
                if (this.gridTiles.includes(gameObject)) {
                    this.editBulletPanel.closeExistPanel()

                    this.unSelectAll()
                    this.selectState = 1
                    gameObject.toggleSelect()
                }
            }
        )

        this.scene.input.on(Phaser.Input.Events.POINTER_UP, (pointer: Phaser.Input.Pointer) => {
            this.selectState = 0
        })
    }

    private createEditTilePanel() {
        this.editBulletPanel = new PanelEditBullet(this.scene)

        this.editBulletPanel.onChangeColor = this.handleChangeColorObjects
        this.editBulletPanel.onRemove = this.handleRemoveObjects
    }

    public setBulletsData(bulletsData: number[]) {
        for (let i = this.bulletsData.length - 1; i >= 0; i--) {
            this.removeBullet(i)
        }
        bulletsData.forEach((color, i) => {
            this.addBullet()
            this.bulletsData[i] = bulletsData[i]
            const tile = this.gridTiles[i]

            tile.setColor(color)
        })
    }

    public addBullet() {
        const tile = new GridTile(this.scene, { row: 0, col: 0 })
        tile.setObjectType('ColorBall')
        this.add(tile)
        this.gridTiles.push(tile)
        tile.setColor(Color.Red)

        this.sendToBack(tile)

        Phaser.Actions.GridAlign([...this.gridTiles, this.addNewBulletButton], {
            width: 10,
            cellWidth: 34,
            cellHeight: 34,
            position: Phaser.Display.Align.CENTER,
            x: -375 / 2 + 17 + 17,
        })

        tile.onSelect = this.handleSelectGridTile
        tile.onUnSelect = this.handleUnSelectGridTile
        tile.onHover = this.handleHoverGridTile
    }

    public removeBullet(index: number) {
        const tile = this.gridTiles[index]

        this.gridTiles = this.gridTiles.filter((t) => t != tile)
        this.bulletsData = [
            ...this.bulletsData.slice(0, index),
            ...this.bulletsData.slice(index + 1, this.bulletsData.length),
        ]

        tile.kill()
        this.remove(tile)

        Phaser.Actions.GridAlign([...this.gridTiles, this.addNewBulletButton], {
            width: 10,
            cellWidth: 34,
            cellHeight: 34,
            position: Phaser.Display.Align.CENTER,
            x: -375 / 2 + 17 + 17,
        })

        return
    }

    private handleSelectGridTile = (gridTile: GridTile) => {
        this.selectingTiles.push(gridTile)

        const { x, y } = gridTile.getWorldPosition()

        this.editBulletPanel.open(x, y - 40)
    }

    private handleUnSelectGridTile = (gridTile: GridTile) => {
        this.selectingTiles = this.selectingTiles.filter((t) => t != gridTile)

        if (this.selectingTiles.length === 0) {
            this.editBulletPanel.close()
        } else {
            const g = this.selectingTiles[this.selectingTiles.length - 1]
            this.editBulletPanel.open(g.x, g.y - 40)
        }
    }

    private handleHoverGridTile = (gridTile: GridTile) => {
        this.removeBulletButton.revive()
        this.removeBulletButton.setPosition(gridTile.x + 34 * 0.35, gridTile.y + 34 * 0.35)
        this.removeBulletButton.onClick = this.handleRemoveBullet(this.gridTiles.indexOf(gridTile))

        if (this.selectState === 1) {
            gridTile.select()
        } else if (this.selectState === -1) {
            gridTile.unSelect()
        }
    }

    private handleAddBullet = () => {
        this.addBullet()
        this.bulletsData.push(Color.Red)
    }

    private handleRemoveBullet = (index: number) => () => {
        this.removeBullet(index)
        this.removeBulletButton.kill()
    }

    private handleChangeColorObjects = (color?: number) => {
        this.selectingTiles.forEach((t) => {
            t.setColor(color)
        })
    }

    private handleRemoveObjects = () => {
        this.selectingTiles.forEach((t) => {
            t.setEmpty()
            t.unSelect()
        })
    }

    public getBulletData() {
        const res = this.gridTiles.map((o) => o.tileData.color)
        return res.filter((x) => x != undefined) as number[]
    }

    private unSelectAll() {
        this.selectingTiles.forEach((t) => {
            t.unSelect()
        })
        this.selectingTiles = []
    }
}

export default BulletEditor
