import DEPTH_OBJECTS from '@/game/constants/depth'
import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class LampPreview extends BasePreview {
    private image: Phaser.GameObjects.Image
    private glow: Phaser.GameObjects.Image

    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'Lamp'

        this.image = scene.make.image({
            key: KEY,
            frame: FRAME.GHOST,
        })
        this.image.setWorldSize(45.5 * 0.9, 45.5 * 0.9)
        this.setSize(34, 34)

        this.glow = this.scene.make.image({
            key: KEY,
            frame: FRAME.LAMP_GLOW,
        })

        this.glow.setDepth(DEPTH_OBJECTS.BALL - 1)
        this.glow.setWorldSize(50, 50)

        this.add([this.image, this.glow])

        this.moveBelow(this.glow, this.image)

        scene.add.existing(this)
    }

    public setStatus(value = 0): void {
        super.setStatus(value)
        if (value == 0) {
            this.glow.setActive(false).setVisible(false)
        } else {
            this.glow.setActive(true).setVisible(true)
        }
    }
}

export default LampPreview
