import { Color } from '@/game/gameplay/types/Color'
import GridTile from '../tiles/GridTile'
import BasePanels from './BasePanels'

class ChangeColorPanel extends BasePanels {
    public onChangeColor: Function

    private objects: GridTile[] = []

    private isHasRandomColor = true
    constructor(scene: Phaser.Scene, randomColor = true) {
        super(scene)
        this.isHasRandomColor = randomColor

        this.createObjects()
    }

    private createObjects() {
        const cellWidth = 40
        const cellHeight = 40
        const width = 4
        const height = 5

        this.createBackground(cellWidth * width, cellHeight * height)

        this.createRedBall()
        this.createBlueBall()
        this.createGreenBall()
        this.createYellowBall()
        this.createPinkBall()
        this.createVioletBall()
        this.createCyanBall()
        this.createOrangeBall()
        this.createRedHalfBall()
        this.createBlueHalfBall()
        this.createGreenHalfBall()
        this.createYellowHalfBall()
        this.createPinkHalfBall()
        this.createVioletHalfBall()
        this.createCyanHalfBall()
        this.createOrangeHalfBall()

        if (this.isHasRandomColor) {
            this.createRandomBall()
            this.createRandomHalfBall()
        }

        Phaser.Actions.GridAlign(this.objects, {
            cellHeight,
            cellWidth,
            width,
            height,
            position: Phaser.Display.Align.CENTER,
            x: -(cellWidth * width) / 2 + cellWidth / 2,
            y: -(cellHeight * height) / 2 + cellHeight / 2,
        })

        this.scene.input.on(
            Phaser.Input.Events.GAMEOBJECT_DOWN,
            (pointer: Phaser.Input.Pointer, gameObject: any) => {
                if (this.objects.includes(gameObject)) {
                    gameObject.toggleSelect()
                }
            }
        )
    }

    private createRedBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Red)
        object.onSelect = this.handleSelect(Color.Red)
        this.objects.push(object)
        this.add(object)
    }

    private createBlueBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Blue)
        object.onSelect = this.handleSelect(Color.Blue)
        this.objects.push(object)
        this.add(object)
    }

    private createGreenBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Green)
        object.onSelect = this.handleSelect(Color.Green)
        this.objects.push(object)
        this.add(object)
    }

    private createYellowBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Yellow)
        object.onSelect = this.handleSelect(Color.Yellow)
        this.objects.push(object)
        this.add(object)
    }

    private createGrayBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Gray)
        object.onSelect = this.handleSelect(Color.Gray)
        this.objects.push(object)
        this.add(object)
    }

    private createBlackBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Black)
        object.onSelect = this.handleSelect(Color.Black)
        this.objects.push(object)
        this.add(object)
    }

    private createPinkBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Pink)
        object.onSelect = this.handleSelect(Color.Pink)
        this.objects.push(object)
        this.add(object)
    }

    private createVioletBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Violet)
        object.onSelect = this.handleSelect(Color.Violet)
        this.objects.push(object)
        this.add(object)
    }

    private createCyanBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Cyan)
        object.onSelect = this.handleSelect(Color.Cyan)
        this.objects.push(object)
        this.add(object)
    }

    private createOrangeBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.setColor(Color.Orange)
        object.onSelect = this.handleSelect(Color.Orange)
        this.objects.push(object)
        this.add(object)
    }

    private createRandomBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('ColorBall')
        object.onSelect = this.handleSelect()
        this.objects.push(object)
        this.add(object)
    }

    private createRedHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.setSubColor(Color.Red)
        object.onSelect = this.handleSelect(Color.Red, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private createBlueHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.setSubColor(Color.Blue)
        object.onSelect = this.handleSelect(Color.Blue, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private createGreenHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.setSubColor(Color.Green)
        object.onSelect = this.handleSelect(Color.Green, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private createYellowHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.setSubColor(Color.Yellow)
        object.onSelect = this.handleSelect(Color.Yellow, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private createPinkHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.setSubColor(Color.Pink)
        object.onSelect = this.handleSelect(Color.Pink, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private createVioletHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.setSubColor(Color.Violet)
        object.onSelect = this.handleSelect(Color.Violet, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private createCyanHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.setSubColor(Color.Cyan)
        object.onSelect = this.handleSelect(Color.Cyan, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private createOrangeHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.setSubColor(Color.Orange)
        object.onSelect = this.handleSelect(Color.Orange, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private createRandomHalfBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.setObjectType('TwoColorsBall')
        object.onSelect = this.handleSelect(-1, 'SubColor')
        this.objects.push(object)
        this.add(object)
    }

    private handleSelect = (color?: number, type?: string) => () => {
        this.onChangeColor && this.onChangeColor(color, type)
        this.close()
    }

    open(x?: number, y?: number): void {
        super.open(x, y)
        this.objects.forEach((o) => o.unSelect())

        const min = 90

        if (this.x < min) {
            this.x = min
        }

        if (this.x > 375 - min) {
            this.x = 375 - min
        }
    }
}

export default ChangeColorPanel
