import SPRITES from '@/game/constants/resources/sprites'
import DEPTH_OBJECT_LEVEL_EDITOR from '../constants/depth_level_editor'
import BasePreview from '../preview/BasePreview'

const { KEY, FRAME } = SPRITES.EDITOR
class BaseTile extends Phaser.GameObjects.Container {
    public preview: BasePreview
    public overlayImage: Phaser.GameObjects.Image
    public selectedImage: Phaser.GameObjects.Image
    public subSelectedImage: Phaser.GameObjects.Image

    public onSelect?: Function
    public onUnSelect?: Function
    public onHover?: Function
    public onUnHover?: Function

    public isSelected = false

    constructor(scene: Phaser.Scene, width: number, height: number) {
        super(scene)

        this.setSize(width, height)
        this.createOverlayImage()
        this.createSelectedImage()

        this.listenEvent()
        this.setDepth(DEPTH_OBJECT_LEVEL_EDITOR.OBJECT)
        scene.add.existing(this)
    }

    public reset = () => {
        this.unSelect()
        this.unHover()
    }

    private createOverlayImage() {
        this.overlayImage = this.scene.make.image({
            key: KEY,
            frame: FRAME.BUBBLE_HOVER,
        })

        this.overlayImage.setWorldSize(this.width, this.height)
        this.overlayImage.kill()
        this.overlayImage.setAlpha(0.5)
        this.overlayImage.setDepth(20)
        this.add(this.overlayImage)
    }

    private createSelectedImage() {
        this.selectedImage = this.scene.make.image({
            key: KEY,
            frame: FRAME.BUBBLE_SELECTED,
        })

        this.selectedImage.setWorldSize(this.width, this.height)
        this.selectedImage.kill()
        this.selectedImage.setDepth(25)

        this.subSelectedImage = this.scene.make.image({
            key: KEY,
            frame: FRAME.BUBBLE_SELECTED,
        })

        this.subSelectedImage.setWorldSize(this.width, this.height)
        this.subSelectedImage.kill()
        this.subSelectedImage.setDepth(25)
        this.subSelectedImage.setTint(0xff0000)
        this.add([this.selectedImage, this.subSelectedImage])
    }

    private listenEvent() {
        this.setInteractive({
            useHandCursor: true,
        })

        this.on(Phaser.Input.Events.POINTER_OVER, this.hover)
        this.on(Phaser.Input.Events.POINTER_OUT, this.unHover)
    }

    setPreview(preview: BasePreview) {
        this.preview?.kill()
        this.remove(this.preview)
        this.preview = preview
        this.preview.revive()
        this.preview.setPosition(0, 0)
        this.add(preview)
        this.sendToBack(preview)
        // this.preview.setDisplaySize(this.width, this.height)
    }

    toggleSelect = () => {
        if (this.isSelected) {
            this.unSelect()
        } else {
            this.select()
        }
    }

    select = () => {
        if (this.isSelected) return

        this.isSelected = true
        this.selectedImage.revive()

        this.onSelect && this.onSelect(this)

        this.overlayImage.kill()
    }

    unSelect = () => {
        if (!this.isSelected) return

        this.isSelected = false
        this.selectedImage.kill()

        this.onUnSelect && this.onUnSelect(this)
    }

    hover = (pointer: Phaser.Input.Pointer) => {
        this.overlayImage.revive()

        this.onHover && this.onHover(this, pointer)
    }

    unHover = () => {
        this.overlayImage.kill()

        this.onUnHover && this.onUnHover(this)
    }
}

export default BaseTile
