import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class PlusMinusBallPreview extends BasePreview {
    private image: Phaser.GameObjects.Image

    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'PlusMinusBall'

        this.image = scene.make.image({
            key: KEY,
            frame: FRAME.PLUS_BALL,
        })
        this.image.setWorldSize(34, 34)
        this.setSize(34, 34)

        this.add(this.image)

        scene.add.existing(this)
    }

    public setStatus(value = 0): void {
        super.setStatus(value)
        if (value > 0) {
            this.image.setFrame(FRAME.PLUS_BALL)
        } else {
            this.image.setFrame(FRAME.MINUS_BALL)
        }
    }
}

export default PlusMinusBallPreview
