import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class SwitchBlackHolePreview extends BasePreview {
    private image: Phaser.GameObjects.Image

    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'SwitchBlackHole'

        this.image = scene.make.image({
            key: KEY,
            frame: FRAME.SWITCH_BLACK_HOLE,
        })
        this.image.setWorldSize(34, 34)
        this.setSize(34, 34)

        this.add(this.image)

        this.image.setTint(0xffffff)

        scene.add.existing(this)
    }

    public setStatus(status?: number | undefined): void {
        super.setStatus(status)

        if (status == 1) {
            this.image.setTint(0xffffff)
        } else {
            this.image.setTint(0x7f7f7f)
        }
    }
}

export default SwitchBlackHolePreview
