import ReuseScroller from '@/game/components/ReuseScroller'
import ColorBallPreview from '../preview/ColorBallPreview'
import ObjectCountBlock from './ObjectCountBlock'

class CountContainer extends Phaser.GameObjects.Container {
    public scroller: ReuseScroller
    public objectCountBlocks: ObjectCountBlock[] = []
    public colorObjects: ColorBallPreview[] = []
    public objectCountSpecialBlocks: ObjectCountBlock[] = []

    constructor(scene: Phaser.Scene) {
        super(scene)
        this.scene.add.existing(this)

        this.setSize(375, 100)
    }

    public clearObjects(): void {
        this.objectCountBlocks.forEach((object) => {
            object.destroy()
        })
        this.objectCountBlocks = []

        this.colorObjects.forEach((object) => {
            object.destroy()
        })
        this.colorObjects = []

        this.objectCountSpecialBlocks.forEach((object) => {
            object.destroy()
        })
        this.objectCountSpecialBlocks = []
    }

    public updateObjects(
        count: { [key: string]: number },
        colors: number[],
        countSpecial: { [key: string]: number },
        countGroup: {
            [key: string]: number
        }
    ) {
        this.clearObjects()

        this.updateCountBlocks(count)
        this.updateColorCountBlocks(colors)
        this.updateCountSpecialBlocks(countSpecial)
        this.updateCountGroup(countGroup)

        this.alignObjects()
    }

    private updateCountGroup(countGroup: { [key: string]: number }): void {
        const typesColorTiles: string[] = [
            'ThunderBall',
            'ColorBall',
            'QuestionMarkBall',
            'GemBall',
            'TwoColorsBall',
        ]
        const colorBlocks: ObjectCountBlock[] = []
        const colorlessBlocks: ObjectCountBlock[] = []

        this.objectCountBlocks.forEach((block) => {
            if (typesColorTiles.includes(block.preview.typePreview)) {
                colorBlocks.push(block)
            } else {
                colorlessBlocks.push(block)
            }
        })

        if (colorBlocks.length > 0) {
            let colorGroup = 0
            Object.keys(countGroup).forEach((key) => {
                const group = countGroup[key]
                if (typesColorTiles.includes(key)) {
                    colorGroup += group
                }
            })
            colorBlocks[0].setGroupText(colorGroup)
            colorBlocks[0].align(true)
        }

        if (colorlessBlocks.length > 0) {
            Object.keys(countGroup).forEach((key) => {
                const group = countGroup[key]
                if (!typesColorTiles.includes(key)) {
                    const block = colorlessBlocks.find((block) => block.preview.typePreview === key)
                    if (block) {
                        block.setGroupText(group)
                        block.align(true)
                    }
                }
            })
        }
    }

    private updateCountBlocks(count: { [key: string]: number }): void {
        Object.keys(count).forEach((type) => {
            const object = new ObjectCountBlock(this.scene, type)
            object.setCountText(count[type])
            this.add(object)
            this.objectCountBlocks.push(object)
        })
    }

    private updateColorCountBlocks(colors: number[]): void {
        colors.forEach((color) => {
            const preview = new ColorBallPreview(this.scene)
            preview.setColor(color)
            this.colorObjects.push(preview)
            this.add(preview)
        })
    }

    private updateCountSpecialBlocks(countSpecial: { [key: string]: number }) {
        Object.keys(countSpecial).forEach((type) => {
            const object = new ObjectCountBlock(this.scene, type)
            object.setCountText(countSpecial[type])
            this.add(object)
            this.objectCountSpecialBlocks.push(object)
        })
    }

    private alignObjects(): void {
        const height = 80 - 40 * Math.ceil(this.objectCountBlocks.length / 4)

        Phaser.Actions.GridAlign(this.objectCountBlocks, {
            width: 4,
            height: Math.ceil(this.objectCountBlocks.length / 4),
            cellWidth: 90,
            cellHeight: 40,
            x: -375 / 4,
            y: height,
        })

        Phaser.Actions.GridAlign(this.colorObjects, {
            width: 8,
            height: Math.ceil(this.colorObjects.length / 8),
            cellWidth: 42,
            cellHeight: 42,
            x: -375 / 2 + 42,
            y: height - 60 - 42 * Math.ceil(this.colorObjects.length / 8),
        })

        Phaser.Actions.GridAlign(this.objectCountSpecialBlocks, {
            width: 4,
            height: Math.ceil(this.objectCountSpecialBlocks.length / 4),
            cellWidth: 90,
            cellHeight: 40,
            x: -375 / 4,
            y: height - 100 - 40 * Math.ceil(this.objectCountSpecialBlocks.length / 4),
        })
    }
}
export default CountContainer
