import Button from '@/game/components/Button'
import SPRITES from '@/game/constants/resources/sprites'
import BasePanels from './BasePanels'
import ChangeColorPanel from './ChangeColorPanel'

const { KEY, FRAME } = SPRITES.EDITOR

class PanelEditBullet extends BasePanels {
    private changeColorButton: Button
    private removeButton: Button

    public onChangeColor: Function
    public onRemove: Function

    private changeColorPanel: ChangeColorPanel

    private panels: BasePanels[] = []

    constructor(scene: Phaser.Scene) {
        super(scene)

        this.createPanels()

        this.createChangeColorButton()
        this.createRemoveButton()
    }

    private createPanels() {
        this.changeColorPanel = new ChangeColorPanel(this.scene, false)
        this.changeColorPanel.onChangeColor = (objectType?: number) => {
            this.onChangeColor && this.onChangeColor(objectType)
            this.open()
        }

        this.panels.push(this.changeColorPanel)
    }

    private createChangeColorButton() {
        this.changeColorButton = new Button(this.scene, KEY, FRAME.FILL_BUTTON, 20, 20)
        this.changeColorButton.setPosition(-12, 0)

        this.changeColorButton.onClick = () => {
            this.changeColorPanel.open(this.x, this.y - 40)
            this.close()
        }

        this.add(this.changeColorButton)
    }

    private createRemoveButton() {
        this.removeButton = new Button(this.scene, KEY, FRAME.REMOVE_BUTTON, 20, 20)
        this.removeButton.setPosition(12, 0)

        this.removeButton.onClick = () => {
            this.onRemove()
        }

        this.add(this.removeButton)
    }

    open(x?: number, y?: number): void {
        super.open(x, y)

        const min = 30

        if (this.x < min) {
            this.x = min
        }

        if (this.x > 375 - min) {
            this.x = 375 - min
        }
    }

    public closeExistPanel() {
        const isExist = this.panels.some((p) => p.visible)
        this.panels.forEach((p) => p.close())

        return isExist
    }
}

export default PanelEditBullet
