import Button from '@/game/components/Button'
import SPRITES from '@/game/constants/resources/sprites'
import AddObjectPanel from './AddObjectPanel'
import AddSubObjectPanel from './AddSubObjectPanel'
import BasePanels from './BasePanels'
import ChangeColorPanel from './ChangeColorPanel'

const { KEY, FRAME } = SPRITES.EDITOR

class PanelEditGridTile extends BasePanels {
    private addObjectButton: Button
    private addSubObjectButton: Button
    private changeColorButton: Button
    private removeButton: Button
    private moveKeyButton: Button

    public onAddObject: Function
    public onAddSubObject: Function
    public onChangeColor: Function
    public onRemove: Function
    public onMovingKey: Function

    private addObjectPanel: AddObjectPanel
    private changeColorPanel: ChangeColorPanel
    private addSubObjectPanel: AddSubObjectPanel

    private panels: BasePanels[] = []

    constructor(scene: Phaser.Scene) {
        super(scene)

        this.createPanels()

        this.createAddObjectButton()
        this.createChangeColorButton()
        this.createAddSubObjectButton()
        this.createRemoveButton()
        this.createMoveKeyButton()
    }

    private createPanels() {
        this.addObjectPanel = new AddObjectPanel(this.scene)
        this.addObjectPanel.onAddObject = (objectType?: string, value?: number) => {
            this.onAddObject && this.onAddObject(objectType, value)
            this.open()
        }

        this.changeColorPanel = new ChangeColorPanel(this.scene)
        this.changeColorPanel.onChangeColor = (objectType?: number, type?: string) => {
            this.onChangeColor && this.onChangeColor(objectType, type)
            this.open()
        }

        this.addSubObjectPanel = new AddSubObjectPanel(this.scene)
        this.addSubObjectPanel.onAddSubObject = (objectType?: string, value?: number) => {
            this.onAddSubObject && this.onAddSubObject(objectType, value)
            this.open()
        }

        this.panels.push(this.addObjectPanel, this.changeColorPanel, this.addSubObjectPanel)
    }

    private createAddObjectButton() {
        this.addObjectButton = new Button(this.scene, KEY, FRAME.EDIT_BUTTON, 20, 20)
        this.addObjectButton.setPosition(-39, 0)

        this.addObjectButton.onClick = () => {
            this.addObjectPanel.open(this.x, this.y - 40)
            this.close()
        }

        this.add(this.addObjectButton)
    }

    private createChangeColorButton() {
        this.changeColorButton = new Button(this.scene, KEY, FRAME.FILL_BUTTON, 20, 20)
        this.changeColorButton.setPosition(-12, 0)

        this.changeColorButton.onClick = () => {
            this.changeColorPanel.open(this.x, this.y - 40)
            this.close()
        }

        this.add(this.changeColorButton)
    }

    private createAddSubObjectButton() {
        this.addSubObjectButton = new Button(this.scene, KEY, FRAME.ADD_BUTTON, 20, 20)
        this.addSubObjectButton.setPosition(12, 0)

        this.addSubObjectButton.onClick = () => {
            this.addSubObjectPanel.open(this.x, this.y - 40)
            this.close()
        }

        this.add(this.addSubObjectButton)
    }

    private createRemoveButton() {
        this.removeButton = new Button(this.scene, KEY, FRAME.REMOVE_BUTTON, 20, 20)
        this.removeButton.setPosition(39, 0)

        this.removeButton.onClick = () => {
            this.onRemove()
        }

        this.add(this.removeButton)
    }

    private createMoveKeyButton() {
        const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS
        this.moveKeyButton = new Button(this.scene, KEY, FRAME.KEY, 20, 20)
        this.moveKeyButton.setPosition(0, -18)

        this.moveKeyButton.onClick = () => {
            this.onMovingKey()
        }

        this.moveKeyButton.setVisible(false)

        this.add(this.moveKeyButton)
    }

    open(x?: number, y?: number, showMoveKeyButton = false): void {
        super.open(x, y)

        const min = 60

        if (showMoveKeyButton) {
            this.moveKeyButton.setVisible(true)
            this.moveKeyButton.setDisabled(false)
        } else {
            this.moveKeyButton.setVisible(false)
            this.moveKeyButton.setDisabled(true)
        }

        if (this.x < min) {
            this.x = min
        }

        if (this.x > 375 - min) {
            this.x = 375 - min
        }
    }

    public closeExistPanel() {
        const isExist = this.panels.some((p) => p.visible)
        this.panels.forEach((p) => p.close())

        return isExist
    }
}

export default PanelEditGridTile
