import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class MirrorBallPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'MirrorBall'

        const mirrorBall = scene.make.image({
            key: KEY,
            frame: FRAME.BALL_MIRROR,
        })
        mirrorBall.setWorldSize(34, 34)
        this.setSize(34, 34)

        this.add(mirrorBall)

        scene.add.existing(this)
    }
}

export default MirrorBallPreview
