import GridTile from '../editor/tiles/GridTile'
import GridEditor from '../GridEditor'

export class BaseFunction {
    public gridEditor: GridEditor

    constructor(gridEditor: GridEditor) {
        this.gridEditor = gridEditor
    }

    public getTopLeftInGridTiles(selectingTiles: GridTile[]): GridTile {
        let result = selectingTiles[0]

        selectingTiles.forEach((tile) => {
            if (tile.row < result.row) {
                result = tile
                return
            }

            if (tile.row === result.row && tile.col < result.col) {
                result = tile
                return
            }
        })
        return result
    }
}
