export const getPreviewClass = function (
    type:
        | BubblePopOrigin.GameObjects.TypeGridObjectName
        | BubblePopOrigin.GameObjects.TypeSubGridObjectName
        | string
): typeof BasePreview {
    switch (type) {
        case 'Bat':
            return BatPreview
        case 'BlackHole':
            return BlackHolePreview
        case 'BombDrug':
            return BombDrugPreview
        case 'Candle':
            return CandlePreview
        case 'ColorBall':
            return ColorBallPreview
        case 'ColorBomb':
            return ColorBombPreview
        case 'EarthenPot':
            return EarthenPotPreview
        case 'ElectricBall':
            return ElectricBallPreview
        case 'EmptyBall':
            return EmptyBallPreview
        case 'GemBall':
            return GemBallPreview
        case 'HexagonWire':
            return HexagonWirePreview
        case 'IronBoard':
            return IronBoardPreview
        case 'IronShell':
            return IronShellPreview
        case 'KeyBall':
            return KeyBallPreview
        case 'Ladybird':
            return LadybirdPreview
        case 'Lamp':
            return LampPreview
        case 'LavaBall':
            return LavaBallPreview
        case 'Leaves':
            return LeavesPreview
        case 'LuckyPouch':
            return LuckyPouchPreview
        case 'MirrorBall':
            return MirrorBallPreview
        case 'Mud':
            return MudPreview
        case 'Mummy':
            return MummyPreview
        case 'PaintPot':
            return PaintPotPreview
        case 'PlusMinusBall':
            return PlusMinusBallPreview
        case 'QuestionMarkBall':
            return QuestionMarkBallPreview
        case 'RandomDirectionElectricBall':
            return RandomDirectionElectricBallPreview
        case 'RelicMask':
            return RelicMaskPreview
        case 'RotationWheel':
            return RotationWheelPreview
        case 'SlateStone':
            return SlateStonePreview
        case 'Spider':
            return SpiderPreview
        case 'SpiderWeb':
            return SpiderWebPreview
        case 'Stone':
            return StonePreview
        case 'SubSlateStone':
            return SubSlateStonePreview
        case 'SwitchBlackHole':
            return SwitchBlackHolePreview
        case 'ThreeThundersBall':
            return ThreeThundersBallPreview
        case 'TwoColorsBall':
            return TwoColorsBallPreview
        case 'WhiteBall':
            return WhiteBallPreview
        case 'Thunder':
            return ThunderPreview
        case 'WhirlDirectionBall':
            return WhirlDirectionPreview
    }

    return BasePreview
}
