import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.EDITOR

class EmptyTilePreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        const bubbleTransparent = scene.make.image({
            key: KEY,
            frame: FRAME.BUBBLE_TRANSPARENT,
        })
        bubbleTransparent.setWorldSize(34, 34)
        this.setSize(34, 34)

        this.add(bubbleTransparent)

        this.setAlpha(0.5)

        scene.add.existing(this)
    }
}

export default EmptyTilePreview
