import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.FIRST_10_LEVELS_GAME_OBJECTS

class BombDrugPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'BombDrug'

        const image = scene.make.image({
            key: KEY,
            frame: FRAME.BOMB_DRUG,
        })
        image.setWorldSize(34, 34)
        this.setSize(34, 34)

        this.add(image)

        scene.add.existing(this)
    }
}

export default BombDrugPreview
