import SPRITES from '@/game/constants/resources/sprites'
import { Color } from '@/game/gameplay/types/Color'
import ColorBallPreview from './ColorBallPreview'
import PreviewSnapshot from './PreviewSnapshot'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class TwoColorsBallPreview extends ColorBallPreview {
    public subImage: Phaser.GameObjects.Image
    public color: number
    public subColor?: number

    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'TwoColorsBall'

        const subImage = scene.make.image({
            key: KEY,
            frame: FRAME.TWO_COLORS_RANDOM,
        })

        subImage.setWorldSize(26, 26)
        subImage.setPosition(this.x + 3, this.y - 3)
        this.subImage = subImage
        this.add(subImage)

        this.subColor = undefined
        this.color = -1
        scene.add.existing(this)
    }

    setRandomSubColor() {
        this.subColor = undefined
        this.subImage.setFrame(FRAME.TWO_COLORS_RANDOM)
    }

    setSubColor(color?: number) {
        this.subImage.setTexture(KEY)
        switch (color) {
            case Color.Red:
                this.subImage.setFrame(FRAME.TWO_COLORS_RED)
                break

            case Color.Green:
                this.subImage.setFrame(FRAME.TWO_COLORS_GREEN)
                break

            case Color.Blue:
                this.subImage.setFrame(FRAME.TWO_COLORS_BLUE)
                break

            case Color.Yellow:
                this.subImage.setFrame(FRAME.TWO_COLORS_YELLOW)
                break

            case Color.Pink:
                this.subImage.setFrame(FRAME.TWO_COLORS_PINK)
                break

            case Color.Violet:
                this.subImage.setFrame(FRAME.TWO_COLORS_VIOLET)
                break

            case Color.Cyan:
                this.subImage.setFrame(FRAME.TWO_COLORS_CYAN)
                break

            case Color.Orange:
                this.subImage.setFrame(FRAME.TWO_COLORS_ORANGE)
                break

            default:
                this.subImage.setFrame(FRAME.TWO_COLORS_RANDOM)
                break
        }

        this.subColor = color || -1
    }

    public getPreviewSnapshot(): PreviewSnapshot {
        return new PreviewSnapshot(this.typePreview, this.color, this.status, this.subColor)
    }
}

export default TwoColorsBallPreview
