import BatPreview from '../preview/BatPreview'
import BlackHolePreview from '../preview/BlackHolePreview'
import BombDrugPreview from '../preview/BombDrugPreview'
import ColorBallPreview from '../preview/ColorBallPreview'
import EarthenPotPreview from '../preview/EarthenPotPreview'
import ElectricBallPreview from '../preview/ElectricBallPreview'
import EmptyTilePreview from '../preview/EmptyTilePreview'
import GemBallPreview from '../preview/GemBallPreview'
import HexagonWirePreview from '../preview/HexagonWirePreview'
import LavaBallPreview from '../preview/LavaBallPreview'
import MummyPreview from '../preview/MummyPreview'
import RandomDirectionElectricBallPreview from '../preview/RandomDirectionElectricBallPreview'
import LeavesPreview from '../preview/LeavesPreview'
import PlusMinusBallPreview from '../preview/PlusMinusBallPreview'
import QuestionMarkBallPreview from '../preview/QuestionMarkBallPreview'
import StonePreview from '../preview/StonePreview'
import ThunderBallPreview from '../preview/ThunderBallPreview'
import WhiteBallPreview from '../preview/WhiteBallPreview'
import BaseTile from './BaseTile'
import LampPreview from '../preview/LampPreview'
import IronShellPreview from '../preview/IronShellPrevew'
import BasePreview from '../preview/BasePreview'
import CandlePreview from '../preview/CandlePreview'
import TwoColorsBallPreview from '../preview/TwoColorsBallPreview'
import RotationWheelPreview from '../preview/RotationWheelPreview'
import DEPTH_OBJECT_LEVEL_EDITOR from '../constants/depth_level_editor'
import MirrorBallPreview from '../preview/MirrorBallPreview'
import SpiderWebPreview from '../preview/SpiderWebPreview'
import ColorBombPreview from '../preview/ColorBombPreview'
import ThreeThundersBallPreview from '../preview/ThreeThundersBallPreview'
import SpiderPreview from '../preview/SpiderPreview'
import LadybirdPreview from '../preview/LadybirdPreview'
import SwitchBlackHolePreview from '../preview/SwitchBlackHolePreview'
import EmptyBallPreview from '../preview/EmptyBallPreview'
import SlateStonePreview from '../preview/SlateStonePreview'
import SubSlateStonePreview from '../preview/SubSlateStonePrview'
import LuckyPouchPreview from '../preview/LuckyPouchPreview'
import KeyBallPreview from '../preview/KeyBallPreview'
import IronBoardPreview from '../preview/IronBoardPreview'
import RelicMaskPreview from '../preview/RelicMaskPreview'
import MudPreview from '../preview/MudPreview'
import SnapshotGridTile from './SnapshotGridTile'
import PaintPotPreview from '../preview/PaintPotPreview'
import ThunderPreview from '../preview/ThunderPreview'
import WhirlDirectionPreview from '../preview/WhirlDirectionPreview'

class GridTile extends BaseTile {
    public tileData: BubblePopOrigin.Data.IGridTileConfig = {}

    public subObjectsPreview: BasePreview[] = []

    public tilesRelate: GridTile[] = [this]

    public row: number
    public col: number

    public isProcess = false
    public isProcessColor = false
    public isProcessSubColor = false

    public processSubGridTileByKeys: {
        [key in BubblePopOrigin.GameObjects.TypeSubGridObjectName]?: boolean
    } = {}

    constructor(scene: Phaser.Scene, gridPosition: IGridPosition) {
        super(scene, 34, 34)

        this.row = gridPosition.row
        this.col = gridPosition.col

        this.setPreview(new EmptyTilePreview(scene))
    }

    public setEmpty() {
        this.setPreview(new EmptyTilePreview(this.scene))
        this.clearSubObjects()
        this.tileData = {}
        const tilesRelate = this.tilesRelate
        this.tilesRelate = []
        tilesRelate.forEach((t) => {
            t.setEmpty()
        })
    }

    public setObjectType = (objectType?: BubblePopOrigin.GameObjects.TypeGridObjectName) => {
        switch (objectType) {
            case 'ColorBall':
                this.setPreview(new ColorBallPreview(this.scene))
                break
            case 'GemBall':
                this.setPreview(new GemBallPreview(this.scene))
                break
            case 'BombDrug':
                this.setPreview(new BombDrugPreview(this.scene))
                break
            case 'ThunderBall':
                this.setPreview(new ThunderBallPreview(this.scene))
                break
            case 'WhiteBall':
                this.setPreview(new WhiteBallPreview(this.scene))
                break
            case 'EarthenPot':
                this.setPreview(new EarthenPotPreview(this.scene))
                break
            case 'Stone':
                this.setPreview(new StonePreview(this.scene))
                break
            case 'ElectricBall':
                this.setPreview(new ElectricBallPreview(this.scene))
                break
            case 'RandomDirectionElectricBall':
                this.setPreview(new RandomDirectionElectricBallPreview(this.scene))
                break
            case 'BlackHole':
                this.setPreview(new BlackHolePreview(this.scene))
                break
            case 'PlusMinusBall':
                this.setPreview(new PlusMinusBallPreview(this.scene))
                break
            case 'LavaBall':
                this.setPreview(new LavaBallPreview(this.scene))
                break
            case 'Mummy':
                this.setPreview(new MummyPreview(this.scene))
                break
            case 'QuestionMarkBall':
                this.setPreview(new QuestionMarkBallPreview(this.scene))
                break
            case 'TwoColorsBall':
                this.setPreview(new TwoColorsBallPreview(this.scene))
                break
            case 'RotationWheel':
                this.setPreview(new RotationWheelPreview(this.scene))
                this.setDepth(DEPTH_OBJECT_LEVEL_EDITOR.MOVE_ROTATION_PREVIEW)
                break
            case 'MirrorBall':
                this.setPreview(new MirrorBallPreview(this.scene))
                break
            case 'Lamp':
                this.setPreview(new LampPreview(this.scene))
                break
            case 'Candle':
                this.setPreview(new CandlePreview(this.scene))
                break
            case 'SwitchBlackHole':
                this.setPreview(new SwitchBlackHolePreview(this.scene))
                break
            case 'EmptyBall':
                this.setPreview(new EmptyBallPreview(this.scene))
                break
            case 'ColorBomb':
                this.setPreview(new ColorBombPreview(this.scene))
                break
            case 'ThreeThundersBall':
                this.setPreview(new ThreeThundersBallPreview(this.scene))
                break
            case 'SlateStone':
                this.setPreview(new SlateStonePreview(this.scene))
                break
            case 'SubSlateStone':
                this.setPreview(new SubSlateStonePreview(this.scene))
                break
            case 'LuckyPouch':
                this.setPreview(new LuckyPouchPreview(this.scene))
                break
            case 'KeyBall':
                this.setPreview(new KeyBallPreview(this.scene))
                break
            case 'RelicMask':
                this.setPreview(new RelicMaskPreview(this.scene))
                break
            case 'PaintPot':
                this.setPreview(new PaintPotPreview(this.scene))
                break
            case 'WhirlDirectionBall':
                this.setPreview(new WhirlDirectionPreview(this.scene))
                break
            default:
                this.setEmpty()
                break
        }

        this.tileData.objectType = objectType
        delete this.tileData.color
        delete this.tileData.status
        delete this.tileData.subColor
    }

    private getSubObjectClass(key: BubblePopOrigin.GameObjects.TypeSubGridObjectName) {
        switch (key) {
            case 'HexagonWire':
                return HexagonWirePreview
            case 'Bat':
                return BatPreview
            case 'Leaves':
                return LeavesPreview
            case 'IronShell':
                return IronShellPreview
            case 'SpiderWeb':
                return SpiderWebPreview
            case 'Spider':
                return SpiderPreview
            case 'Ladybird':
                return LadybirdPreview
            case 'IronBoard':
                return IronBoardPreview
            case 'Mud':
                return MudPreview
            case 'Thunder':
                return ThunderPreview
            default:
                return EmptyTilePreview
        }
    }

    public addSubObjectType(
        subObjectType: BubblePopOrigin.GameObjects.TypeSubGridObjectName,
        value = 0
    ) {
        if (!this.tileData.subObjects) {
            this.tileData.subObjects = []
        }

        const subObject = this.tileData.subObjects.find((x) => x.type === subObjectType)

        const subObjectClass = this.getSubObjectClass(subObjectType)

        if (subObject) {
            subObject.status = value
            this.subObjectsPreview.find((s) => s instanceof subObjectClass)?.setStatus(value)
            return
        }

        this.tileData.subObjects.push({ type: subObjectType, status: value })

        if (subObjectClass != EmptyTilePreview) {
            this.addSubObject(new subObjectClass(this.scene), value)
        }
    }

    private addSubObject(subObject: BasePreview, value?: number) {
        const { x, y } = this.getWorldPosition()
        subObject.setPosition(x, y)
        subObject.setDepth(100)
        subObject.setStatus(value)
        this.subObjectsPreview.push(subObject)
    }

    public clearSubObjects() {
        this.subObjectsPreview.forEach((o) => {
            o.kill()
        })
        this.subObjectsPreview = []
        delete this.tileData.subObjects
    }

    public setColor = (color?: number) => {
        if (!color) {
            delete this.tileData.color
            if (
                this.preview instanceof ColorBallPreview ||
                this.preview instanceof RelicMaskPreview ||
                this.preview instanceof PaintPotPreview
            ) {
                this.preview.setRandomColor()
            }
            return
        }
        if (
            this.preview instanceof ColorBallPreview ||
            this.preview instanceof RelicMaskPreview ||
            this.preview instanceof PaintPotPreview
        ) {
            this.preview.setColor(color)
            this.tileData.color = color
        }
    }

    public setSubColor = (color?: number) => {
        if (!color) {
            delete this.tileData.subColor
            if (this.preview instanceof TwoColorsBallPreview) {
                this.preview.setRandomSubColor()
            }
            return
        }
        if (this.preview instanceof TwoColorsBallPreview) {
            this.preview.setSubColor(color)
            this.tileData.subColor = color
        }
    }

    public setStatus = (status?: number, type?: string) => {
        if (status === undefined || status === 0) {
            delete this.tileData.status
        } else {
            this.tileData.status = status
        }

        this.preview.setStatus(status)
    }

    kill(): void {
        super.kill()
        this.subObjectsPreview.forEach((o) => {
            o.kill()
        })
    }

    revive(): void {
        super.revive()
        this.subObjectsPreview.forEach((o) => {
            o.revive()
        })
    }

    resetPositionSubObject(depth?: number) {
        const { x, y } = this.getWorldPosition()

        this.subObjectsPreview.forEach((o) => {
            o.setPosition(x, y)

            depth && o.setDepth(depth)
        })
    }

    public setTilesRelate(tilesRelate: GridTile[]): void {
        this.tilesRelate = tilesRelate
    }

    public getTilesRelate(): GridTile[] {
        return this.tilesRelate
    }

    public getSnapshotGridTile(): SnapshotGridTile {
        const previewSnapshot = this.preview.getPreviewSnapshot()
        const subObjectSnapshot = this.subObjectsPreview.map((subObject) =>
            subObject.getPreviewSnapshot()
        )

        return new SnapshotGridTile(previewSnapshot, subObjectSnapshot, this.row, this.col)
    }

    public resetProcessed(): void {
        this.isProcess = false
        this.isProcessColor = false
        this.isProcessSubColor = false
        this.processSubGridTileByKeys = {}
    }
}

export default GridTile
