import SPRITES from '@/game/constants/resources/sprites'
import Direction from '@/game/gameplay/types/Direction'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class SlateStonePreview extends BasePreview {
    public direction = Direction.UpRight
    private slateStoneImage: Phaser.GameObjects.Image
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'SlateStone'

        this.slateStoneImage = scene.make.image({
            key: KEY,
            frame: FRAME.SLATE_STONE,
        })
        this.slateStoneImage.setWorldSize((80 * 31.5) / 29, 31.5)
        this.setSize((80 * 31.5) / 29, 31.5)

        this.add(this.slateStoneImage)

        scene.add.existing(this)
    }

    public setStatus(value = 0): void {
        super.setStatus(value)
        switch (value) {
            case 2:
                this.direction = Direction.UpRight
                this.slateStoneImage.setFlipY(true)
                break
            case 1:
                this.direction = Direction.UpLeft
                this.slateStoneImage.setFlipX(true)
                break
            case 0:
                this.direction = Direction.Left
        }

        this.slateStoneImage.setRotation(this.direction)
    }
}

export default SlateStonePreview
