import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class LadybirdPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'Ladybird'

        const ladybird = scene.make.image({
            key: KEY,
            frame: FRAME.LADYBIRD,
        })
        ladybird.setWorldSize(14.5, 15.5)
        ladybird.setFlipX(true)
        this.setSize(14.5, 15.5)

        this.add(ladybird)

        ladybird.setPosition(9, -7)

        scene.add.existing(this)
    }
}

export default LadybirdPreview
