    private handleSelect = (key?: string, value?: number) => () => {
        this.onAddObject && this.onAddObject(key, value)
        this.close()
    }

    open(x?: number, y?: number): void {
        super.open(x, y)
        this.objects.forEach((o) => o.unSelect())
        const min = 130

        if (this.x < min) {
            this.x = min
        }

        if (this.x > 375 - min) {
            this.x = 375 - min
        }
    }
