import SnapshotGridTile from '../editor/tiles/SnapshotGridTile'
import GridEditor from '../GridEditor'
import { BaseFunction } from './BaseFunction'
import { TypeCommand } from './constants/TypeCommand'

class UndoFunction extends BaseFunction {
    private listUndo: SnapshotGridTile[][] = []
    private listReUndo: SnapshotGridTile[][] = []

    constructor(gridEditor: GridEditor) {
        super(gridEditor)
    }

    private isCanUndo(): boolean {
        if (this.listUndo.length > 0) return true
        return false
    }

    public execute(typeAction?: TypeCommand) {
        switch (typeAction) {
            case TypeCommand.RE_UNDO:
                this.reUndo()
                break
            case TypeCommand.UNDO:
            default:
                this.undo()
        }
    }

    private undo(): void {
        if (!this.isCanUndo()) return

        const snapshotGridTiles = this.listUndo.pop()

        if (snapshotGridTiles && snapshotGridTiles.length > 0) {
            this.listReUndo.push(this.getListSnapshotGridTiles())
            this.restoreGridTiles(snapshotGridTiles)
        }
    }

    private reUndo() {
        if (this.listReUndo.length === 0) return

        const snapshotGridTiles = this.listReUndo.pop()

        if (snapshotGridTiles && snapshotGridTiles.length > 0) {
            this.listUndo.push(this.getListSnapshotGridTiles())
            this.restoreGridTiles(snapshotGridTiles)
        }
    }

    public makeBackUp(typeAction?: TypeCommand): void {
        switch (typeAction) {
            case TypeCommand.RE_UNDO:
                this.listReUndo.push(this.getListSnapshotGridTiles())
                break
            case TypeCommand.UNDO:
            default:
                this.listUndo.push(this.getListSnapshotGridTiles())
                this.listReUndo = []
        }
    }

    private getListSnapshotGridTiles(): SnapshotGridTile[] {
        const listSnapshotGridTiles: SnapshotGridTile[] = []

        const gridTiles = this.gridEditor.gridTiles
        gridTiles.forEach((gridTile) => {
            gridTile.forEach((tile) => {
                if (tile.preview.typePreview !== 'SubSlateStone') {
                    listSnapshotGridTiles.push(tile.getSnapshotGridTile())
                }
            })
        })

        return listSnapshotGridTiles
    }

    public restoreGridTiles(snapshotGridTiles: SnapshotGridTile[]) {
        this.gridEditor.clearGrid()
        snapshotGridTiles.forEach((snapshotGridTile) => {
            if (snapshotGridTile.row >= this.gridEditor.gridTiles.length) {
                for (let i = 0; i <= snapshotGridTile.row - this.gridEditor.gridTiles.length; i++) {
                    this.gridEditor.addRow()
                }
            }
            if (
                this.gridEditor.gridTiles[snapshotGridTile.row] &&
                this.gridEditor.gridTiles[snapshotGridTile.row][snapshotGridTile.col]
            ) {
                const gridTile =
                    this.gridEditor.gridTiles[snapshotGridTile.row][snapshotGridTile.col]

                snapshotGridTile.restore(this.gridEditor, gridTile)
            }
        })
    }

    public clear() {
        this.listReUndo = []
        this.listUndo = []
    }
}

export default UndoFunction
