import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class IronShellPreview extends BasePreview {
    private ironShellImage: Phaser.GameObjects.Image
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'IronShell'

        this.ironShellImage = scene.make.image({
            key: KEY,
            frame: FRAME.PREFIX_IRON_SHELL + 0,
        })
        this.ironShellImage.setWorldSize(34, 37.5)

        this.add(this.ironShellImage)

        this.setAlpha(0.5)

        scene.add.existing(this)
    }
    public setStatus(status?: number): void {
        super.setStatus(status)

        if (status) {
            this.ironShellImage.setFrame(FRAME.PREFIX_IRON_SHELL + 5)
        } else {
            this.ironShellImage.setFrame(FRAME.PREFIX_IRON_SHELL + 1)
        }
    }
}

export default IronShellPreview
