import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class LeavesPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'Leaves'

        const image = scene.make.image({
            key: KEY,
            frame: FRAME.LEAVES,
        })
        image.setWorldSize(38, 38)
        this.setSize(34, 34)

        this.add(image)

        this.setAlpha(0.5)

        scene.add.existing(this)
    }
}

export default LeavesPreview
