import FONTS from '@/game/constants/resources/fonts'
import BasePreview from './BasePreview'
class Base2Preview extends BasePreview {
    protected descriptionText: Phaser.GameObjects.BitmapText
    protected createVersionText(text = 'V2') {
        this.descriptionText = this.scene.make.bitmapText({
            font: FONTS.PRIMARY.KEY,
            size: this.scene.fontSize(15),
            text,
            origin: {
                x: 0.5,
                y: 0.5,
            },
            alpha: 0.5,
        })
        this.add(this.descriptionText)
    }
}
export default Base2Preview
