import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.FIRST_10_LEVELS_GAME_OBJECTS

class ThunderPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'Thunder'

        const thunder = scene.make.image({
            key: KEY,
            frame: FRAME.THUNDER2_YELLOW,
        })
        thunder.setTint(0xffffff)
        thunder.setWorldSize(20.5, 28)
        this.setSize(20.5, 28)

        this.add(thunder)

        scene.add.existing(this)
    }
}

export default ThunderPreview
