import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class LavaBallPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'LavaBall'

        const ballTransparent = scene.make.image({
            key: KEY,
            frame: FRAME.FIREFLY_CAP,
        })

        ballTransparent.setWorldSize(34, 34)

        const background = scene.make.image({
            key: KEY,
            frame: FRAME.FIREFLY_EMPTY_BOTTLE,
        })

        background.setWorldSize(34, 34)

        const scale = 1 / this.scene.world.getPixelRatio()

        const firefly1 = scene.make.image({
            key: KEY,
            frame: FRAME.FIREFLY_PREFIX + 0,
        })

        firefly1.setScale(scale)
        firefly1.setPosition(4, 4)

        const firefly2 = scene.make.image({
            key: KEY,
            frame: FRAME.FIREFLY_PREFIX + 0,
        })

        firefly2.setScale(scale * 0.4)
        firefly2.setPosition(-6, -6)
        firefly2.setFlipX(true)

        this.setSize(34, 34)

        this.add([ballTransparent, background, firefly1, firefly2])

        scene.add.existing(this)
    }
}

export default LavaBallPreview
