import GridEditor from '../../GridEditor'
import PreviewSnapshot from '../preview/PreviewSnapshot'
import GridTile from './GridTile'

class SnapshotGridTile {
    previewSnapshot: PreviewSnapshot
    subPreviewSnapshot: PreviewSnapshot[]
    row = 0
    col = 0
    constructor(
        previewSnapShot: PreviewSnapshot,
        subPreviewSnapShot: PreviewSnapshot[],
        row: number,
        col: number
    ) {
        this.previewSnapshot = previewSnapShot
        this.subPreviewSnapshot = subPreviewSnapShot
        this.row = row
        this.col = col
    }

    public restore(gridEditor: GridEditor, tile: GridTile): void {
        const objectType = this.previewSnapshot
            .typePreview as BubblePopOrigin.GameObjects.TypeGridObjectName

        const status = this.previewSnapshot.status
        gridEditor.handleAddObject(tile, objectType, status)
        const color = this.previewSnapshot.color
        if (color !== -1) {
            tile.setColor(color)
        }

        if (this.previewSnapshot.subColor) {
            tile.setSubColor(this.previewSnapshot.subColor)
        }
        tile.clearSubObjects()
        this.subPreviewSnapshot.forEach((subPreview) => {
            const subObjectType =
                subPreview.typePreview as BubblePopOrigin.GameObjects.TypeSubGridObjectName
            const subObjectStatus = subPreview.status
            tile.addSubObjectType(subObjectType, subObjectStatus)
        })
    }
}

export default SnapshotGridTile
