import DEPTH_OBJECTS from '@/game/constants/depth'
import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class CandlePreview extends BasePreview {
    public candleBody: Phaser.GameObjects.Image

    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'Candle'

        this.candleBody = this.scene.make.image({
            key: KEY,
            frame: FRAME.PREFIX_CANDLE + '1',
        })

        this.candleBody.setWorldSize(35, 43.5)

        this.candleBody.setDepth(DEPTH_OBJECTS.EXPLODE + 1)

        this.add(this.candleBody)

        this.scene.add.existing(this)
    }
}

export default CandlePreview
