    private pane: Pane
    private element: HTMLElement
    private starsTargetFolder: FolderApi
    private guidesFolder: FolderApi

    private isEnable: boolean

    private data: BubblePopOrigin.Data.ILevelData

    constructor(scene: LevelEditorScene) {
        this.scene = scene
    }

    private createPane(): void {
        const level = this.scene.level.getLevel()
        this.pane = new Pane({
            title: `Level ${level}`,
            expanded: true,
        })

        this.element = this.pane.element

        this.initPaneConfig()
    }

    private createStarsTargetFolder(): void {
        this.starsTargetFolder = this.pane.addFolder({
            title: 'Stars Target',
            expanded: true,
        })
    }

    private initPaneConfig() {
        const config = {
            opacity: 0.8,
            x: -8,
            y: -8,
            width: 324,
        }

        if (this.element.parentElement) {
            this.element.parentElement.style.top = `${-config.y}px`
            this.element.parentElement.style.left = `${-config.x}px`
            this.element.parentElement.style.width = `${config.width}px`
        }

        this.element.style.opacity = `${config.opacity}`

        this.element.onwheel = ((e: WheelEvent) => {
            const { deltaY } = e
            if (config.y <= -8 && deltaY < 0) return
            if (
                config.y >= this.element.clientHeight - document.body.clientHeight - 8 &&
                deltaY > 0
            )
                return

            config.y += deltaY / 2
            if (this.element.parentElement) {
                this.element.parentElement.style.top = `${-config.y}px`
            }
        }).bind(this)
    }

