        function createNewGuideParams() {
            const newGuideParams = {
                popupType: 'small',
                condition: '',
                spriteName: '',
                title: '',
                message: '',
                hasMask: false,
                maskSize: 0,
                hasHand: false,
                guideType: 'information',
                handPosition: {
                    start: {
                        x: 0,
                        y: 0,
                    },
                    end: { x: 0, y: 0 },
                },
                points: [],
                popupPosition: 'center',
                hasOkButton: false,
                hasArrow: false,
            }
            return newGuideParams
        }

        this.guidesFolder
            .addButton({
                title: 'Add Guide',
            })
            .on('click', () => {
                const newGuideParams = createNewGuideParams()
                if (!this.data.guides) {
                    this.data.guides = [newGuideParams]
                } else {
                    this.data.guides.push(newGuideParams)
                }
                this.createGuide(this.data.guides.length - 1, newGuideParams)
            })

        if (this.data.guides && this.data.guides.length > 0) {
            for (let i = 0; i < this.data.guides.length; i++) {
                this.createGuide(i, this.data.guides[i])
            }
        }
