import GridTile from '../editor/tiles/GridTile'
import SnapshotGridTile from '../editor/tiles/SnapshotGridTile'
import GridEditor from '../GridEditor'
import { BaseFunction } from './BaseFunction'

class CopyPasteFunction extends BaseFunction {
    private snapshotGridTiles: SnapshotGridTile[] = []
    constructor(gridEditor: GridEditor) {
        super(gridEditor)
    }

    public handleCopyTiles(tiles: GridTile[]): void {
        this.snapshotGridTiles = []
        tiles.forEach((tile) => {
            if (tile.preview.typePreview !== 'SubSlateStone') {
                this.snapshotGridTiles.push(tile.getSnapshotGridTile())
            }
        })
    }

    public handlePasteTiles(selectingTiles: GridTile[]): void {
        if (selectingTiles.length === 0 || this.snapshotGridTiles.length === 0) return

        if (this.snapshotGridTiles.length === selectingTiles.length) {
            this.snapshotGridTiles.forEach((snapshotGridTile, index) => {
                snapshotGridTile.restore(this.gridEditor, selectingTiles[index])
            })
            return
        }

        const topLeftGridTile = this.getTopLeftInGridTiles(selectingTiles)
        const topLeftSnapShotGridTile = this.getTopLeftInSnapshotGridTiles()
        let checkSameTypeRow = false
        if (topLeftGridTile.row % 2 === topLeftSnapShotGridTile.row % 2) {
            checkSameTypeRow = true
        }

        this.gridEditor.unSelectAll()
        this.snapshotGridTiles.forEach((snapshotGridTile) => {
            //find row,col
            const row = snapshotGridTile.row - topLeftSnapShotGridTile.row
            let col = snapshotGridTile.col - topLeftSnapShotGridTile.col
            if (!checkSameTypeRow && (row !== 0 || col !== 0)) {
                if (topLeftSnapShotGridTile.row % 2 === 0 && row % 2 !== 0) {
                    col = snapshotGridTile.col - topLeftSnapShotGridTile.col + 1
                }
                if (topLeftSnapShotGridTile.row % 2 !== 0 && row % 2 !== 0) {
                    col = snapshotGridTile.col - topLeftSnapShotGridTile.col - 1
                }
            }
            //restore
            if (
                this.gridEditor.gridTiles[topLeftGridTile.row + row] &&
                this.gridEditor.gridTiles[topLeftGridTile.row + row][topLeftGridTile.col + col]
            ) {
                const gridTile =
                    this.gridEditor.gridTiles[topLeftGridTile.row + row][topLeftGridTile.col + col]
                gridTile.select()
                snapshotGridTile.restore(this.gridEditor, gridTile)
            }
        })
    }

    private getTopLeftInSnapshotGridTiles(): SnapshotGridTile {
        let result = this.snapshotGridTiles[0]

        this.snapshotGridTiles.forEach((snapshotGridTile) => {
            if (snapshotGridTile.row < result.row) {
                result = snapshotGridTile
                return
            }

            if (snapshotGridTile.row === result.row && snapshotGridTile.col < result.col) {
                result = snapshotGridTile
            }
        })

        return result
    }
}

export default CopyPasteFunction
