import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class IronBoardPreview extends BasePreview {
    private ironBoard: Phaser.GameObjects.Image
    private lock: Phaser.GameObjects.Image
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'IronBoard'

        const ironBoard = scene.make.image({
            key: KEY,
            frame: FRAME.IRON_BOARD,
        })
        ironBoard.setWorldSize(37, 42.5)

        this.lock = scene.make.image({
            key: KEY,
            frame: FRAME.IRON_BOARD_LOCK,
        })
        this.lock.setWorldSize(20, 24)

        this.setSize(34, 34)

        this.ironBoard = ironBoard

        this.add([ironBoard, this.lock])

        this.lock.kill()

        this.setAlpha(0.7)

        scene.add.existing(this)
    }

    public setStatus(status = 0): void {
        super.setStatus(status)

        if (status) {
            this.lock.revive()
        } else {
            this.lock.kill()
        }
    }
}

export default IronBoardPreview
