import SPRITES from '@/game/constants/resources/sprites'

const { KEY, FRAME } = SPRITES.EDITOR
class BasePanels extends Phaser.GameObjects.Container {
    constructor(scene: Phaser.Scene) {
        super(scene)
        scene.add.existing(this)

        this.setAlpha(0.85)

        this.close()

        this.setDepth(200)
    }

    createBackground(width: number, height: number) {
        const bg = this.scene.make.image({
            key: KEY,
            frame: FRAME.POPUP,
        })

        bg.setWorldSize(width, height)

        this.setSize(width, height)
        this.add(bg)
    }

    open(x?: number, y?: number) {
        this.revive()

        if (x && y) {
            this.setPosition(x, y)
        }
    }

    close() {
        this.kill()
    }
}

export default BasePanels
