import SPRITES from '@/game/constants/resources/sprites'
import { Color } from '@/game/gameplay/types/Color'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class RelicMaskPreview extends BasePreview {
    public image: Phaser.GameObjects.Image
    public randomImage: Phaser.GameObjects.Image

    constructor(scene: Phaser.Scene) {
        super(scene)
        this.typePreview = 'RelicMask'
        const image = scene.make.image({
            key: KEY,
            frame: FRAME.RELIC_MASK_RANDOM,
        })

        image.setWorldSize(32, 32)
        this.setSize(34, 34)
        this.image = image
        this.add(image)
        this.image.setAlpha(0.8)

        const randomImage = scene.make.image({
            key: SPRITES.EDITOR.KEY,
            frame: SPRITES.EDITOR.FRAME.GENERATE_BUTTON,
        })
        randomImage.setWorldSize(30, 30)
        this.add(randomImage)
        this.randomImage = randomImage
        randomImage.setAlpha(0.7)

        this.color = -1
        scene.add.existing(this)
    }

    setRandomColor() {
        this.color = -1
        this.image.setFrame(FRAME.RELIC_MASK_RANDOM)
        this.randomImage.revive()
        this.image.setAlpha(0.8)
    }

    setColor(color?: number) {
        this.image.setTexture(KEY)
        switch (color) {
            case Color.Red:
                this.image.setFrame(FRAME.RELIC_MASK_RED)
                break

            case Color.Green:
                this.image.setFrame(FRAME.RELIC_MASK_GREEN)
                break

            case Color.Blue:
                this.image.setFrame(FRAME.RELIC_MASK_BLUE)
                break

            case Color.Yellow:
                this.image.setFrame(FRAME.RELIC_MASK_YELLOW)
                break

            case Color.Pink:
                this.image.setFrame(FRAME.RELIC_MASK_PINK)
                break

            case Color.Violet:
                this.image.setFrame(FRAME.RELIC_MASK_PURPLE)
                break

            case Color.Cyan:
                this.image.setFrame(FRAME.RELIC_MASK_SKY_BLUE)
                break

            case Color.Orange:
                this.image.setFrame(FRAME.RELIC_MASK_ORANGE)
                break

            default:
                this.image.setTexture(SPRITES.DEFAULT.KEY)
                this.image.setFrame(SPRITES.DEFAULT.FRAME.BUY_ITEM_RAINBOW_BIG)
                break
        }

        this.color = color || -1

        if (!color) {
            this.randomImage.revive()
            this.image.setAlpha(0.8)
        } else {
            this.randomImage.kill()
            this.image.setAlpha(1)
        }

        this.randomImage.revive()
    }
}

export default RelicMaskPreview
