import GridTile from '../tiles/GridTile'
import BasePanels from './BasePanels'

class AddSubObjectPanel extends BasePanels {
    public onAddSubObject: Function

    private objects: GridTile[] = []

    constructor(scene: Phaser.Scene) {
        super(scene)
        this.createObjects()
    }

    private createObjects() {
        const cellWidth = 40
        const cellHeight = 40
        const width = 4
        const height = 4

        this.createBackground(cellWidth * width, cellHeight * height)

        this.createHexagonWire()
        this.createBat()
        this.createLeaves()
        this.createCloseIronShell()
        this.createOpenIronShell()
        this.createSpiderWeb()
        this.createSpider()
        this.createLadybird()
        this.createIronBoard()
        this.createIronBoardLock()
        this.createMud()
        this.createThunder()
        this.createEmptyBall()

        Phaser.Actions.GridAlign(this.objects, {
            cellHeight,
            cellWidth,
            width,
            height,
            position: Phaser.Display.Align.CENTER,
            x: -(cellWidth * width) / 2 + cellWidth / 2,
            y: -(cellHeight * height) / 2 + cellHeight / 2,
        })

        this.scene.input.on(
            Phaser.Input.Events.GAMEOBJECT_DOWN,
            (pointer: Phaser.Input.Pointer, gameObject: any) => {
                if (this.objects.includes(gameObject)) {
                    gameObject.toggleSelect()
                }
            }
        )
    }

    private createHexagonWire() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('HexagonWire')
        this.objects.push(object)

        object.addSubObjectType('HexagonWire')

        object.kill()
    }

    private createBat() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('Bat')
        this.objects.push(object)

        object.addSubObjectType('Bat')

        object.kill()
    }

    private createLeaves() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('Leaves')
        this.objects.push(object)

        object.addSubObjectType('Leaves')

        object.kill()
    }

    private createCloseIronShell(): void {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)

        object.onSelect = this.handleSelect('IronShell', 0)
        this.objects.push(object)

        object.addSubObjectType('IronShell', 0)

        object.kill()
    }

    private createOpenIronShell(): void {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)

        object.onSelect = this.handleSelect('IronShell', 1)
        this.objects.push(object)

        object.addSubObjectType('IronShell', 1)

        object.kill()
    }

    private createSpiderWeb() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('SpiderWeb')
        this.objects.push(object)

        object.addSubObjectType('SpiderWeb')

        object.kill()
    }

    private createSpider() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('Spider')
        this.objects.push(object)

        object.addSubObjectType('Spider')

        object.kill()
    }

    private createLadybird() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('Ladybird')
        this.objects.push(object)

        object.addSubObjectType('Ladybird')

        object.kill()
    }

    private createIronBoard() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('IronBoard')
        this.objects.push(object)

        object.addSubObjectType('IronBoard')

        object.kill()
    }

    private createIronBoardLock() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('IronBoard', 1)
        this.objects.push(object)

        object.addSubObjectType('IronBoard', 1)

        object.kill()
    }

    private createMud() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('Mud')
        this.objects.push(object)

        object.addSubObjectType('Mud')

        object.kill()
    }

    private createThunder() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        this.add(object)
        object.onSelect = this.handleSelect('Thunder')
        this.objects.push(object)
        object.addSubObjectType('Thunder')
        object.kill()
    }

    private createEmptyBall() {
        const object = new GridTile(this.scene, { row: -1, col: -1 })
        object.onSelect = this.handleSelect()
        this.objects.push(object)
        this.add(object)
    }

    private handleSelect =
        (key?: string, value = 0) =>
        () => {
            this.onAddSubObject && this.onAddSubObject(key, value)
            this.close()
        }

    open(x?: number, y?: number): void {
        super.open(x, y)

        const min = 90

        if (this.x < min) {
            this.x = min
        }

        if (this.x > 375 - min) {
            this.x = 375 - min
        }

        this.objects.forEach((o) => {
            o.unSelect()
            o.resetPositionSubObject(300)
            o.revive()
        })
    }

    close() {
        super.close()
        this.objects &&
            this.objects.forEach((o) => {
                o.kill()
            })
    }
}

export default AddSubObjectPanel
