import SPRITES from '@/game/constants/resources/sprites'
import BasePreview from './BasePreview'

const { KEY, FRAME } = SPRITES.GAMEPLAY.GAME_OBJECTS

class WhiteBallPreview extends BasePreview {
    constructor(scene: Phaser.Scene) {
        super(scene)

        this.typePreview = 'WhiteBall'

        const whiteBall = scene.make.image({
            key: KEY,
            frame: FRAME.BALL_WHITE,
        })
        whiteBall.setWorldSize(34, 34)
        this.setSize(34, 34)

        this.add(whiteBall)

        scene.add.existing(this)
    }
}

export default WhiteBallPreview
